                            </div>
                            <div className="flex items-start gap-2 bg-gray-50 dark:bg-indigo-950/50 p-2 rounded text-[10px] text-gray-500 dark:text-gray-400 italic border border-gray-100 dark:border-indigo-900">
                                <Info size={12} className="shrink-0 mt-0.5" />
                                Disclaimer: These results are based on standard genetic inheritance patterns (Mendelian). This is a theoretical prediction and NOT a diagnosis. Always confirm your baby's blood group with a lab test after birth.
                            </div>
                        </div>

                        {/* Compatibility Alert */}
                        <div className={`p-3 rounded-lg border text-sm flex gap-2 ${
                            bloodData.risk.severity === 'high' ? 'bg-red-50 text-red-800 border-red-200' : 
                            bloodData.risk.severity === 'medium' ? 'bg-yellow-50 text-yellow-800 border-yellow-200' :
