import React, { useState, useEffect, useRef } from 'react';
import { PregnancyCalculations, WeeklyInfo, UserSettings } from '../types';
import { WEEKLY_DATA, FALLBACK_WEEKLY_INFO, SCAN_SCHEDULE, LAB_SCHEDULE, COMORBIDITY_GUIDELINES, MATERNAL_VACCINES, DAILY_TIPS, MATERNAL_AGE_RISKS, OBSTETRIC_HISTORY_RISKS } from '../constants';
import { getPregnancyAdvice } from '../services/geminiService';
import { Button } from './Button';
import { Info, Baby, AlertCircle, Bell, Activity, ChevronLeft, ChevronRight, RotateCcw, Syringe, Sparkles, FlaskConical, ShieldAlert } from 'lucide-react';

interface Props {
  calculations: PregnancyCalculations;
  settings: UserSettings;
}

export const Dashboard: React.FC<Props> = ({ calculations, settings }) => {
  // Use local state for navigation, initialize with actual current week
  const [selectedWeek, setSelectedWeek] = useState(calculations.currentWeek);

  // Reset selected week if calculations change (e.g. profile update)
  useEffect(() => {
    setSelectedWeek(calculations.currentWeek);
  }, [calculations.currentWeek]);

  // Derived calculations for the SELECTED week (for display purposes)
  const displayTrimester = selectedWeek <= 13 ? 1 : selectedWeek <= 27 ? 2 : 3;
  const displayMonth = Math.ceil(selectedWeek / 4.3);
  const displayProgress = Math.min((selectedWeek / 40) * 100, 100);

  const availableWeeks = Object.keys(WEEKLY_DATA).map(Number).sort((a, b) => a - b);
  const closestWeek = availableWeeks.reduce((prev, curr) => 
    Math.abs(curr - selectedWeek) < Math.abs(prev - selectedWeek) ? curr : prev
  );

  const weekInfo: WeeklyInfo = WEEKLY_DATA[selectedWeek] || WEEKLY_DATA[closestWeek] || FALLBACK_WEEKLY_INFO;

  // Filter scans relevant to the selected week range
  const relevantScans = SCAN_SCHEDULE.filter(scan => {
    return (selectedWeek >= scan.weekStart - 1 && selectedWeek <= scan.weekEnd);
  });

  // Filter Lab Tests relevant to current week
  const relevantLabs = LAB_SCHEDULE.filter(lab => {
      // Basic week check
      const isTime = selectedWeek >= lab.weekStart - 1 && selectedWeek <= lab.weekEnd;
      if (!isTime) return false;

      // Condition check
      if (lab.condition) {
          if (lab.condition === 'thyroid' && !settings.comorbidities.includes('thyroid')) return false;
          if (lab.condition === 'anemia' && !settings.comorbidities.includes('anemia')) return false;
          if (lab.condition === 'rh_negative' && (!settings.maternalBloodGroup || !settings.maternalBloodGroup.includes('-'))) return false;
      }
      return true;
  });

  // Filter VACCINES relevant to current week (Maternal)
  const vaccinationsDone = settings.vaccinationsDone || [];
  const upcomingVaccines = MATERNAL_VACCINES.filter(vax => {
    const isDone = vaccinationsDone.includes(vax.id);
    // Show if due within next 4 weeks or overdue
    return !isDone && (selectedWeek >= vax.dueWeekStart - 2 && selectedWeek <= vax.dueWeekEnd + 4);
  });

  const selectedComorbidities = settings.comorbidities || [];

  const [question, setQuestion] = useState('');
  const [aiAnswer, setAiAnswer] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);

  const askAi = async () => {
    if (!question.trim()) return;
    setLoadingAi(true);
    // Pass selectedWeek so AI answers for the context the user is viewing
    const answer = await getPregnancyAdvice(question, selectedWeek);
    setAiAnswer(answer);
    setLoadingAi(false);
  };

  // Navigation Handlers
  const handlePrevWeek = () => {
    if (selectedWeek > 1) setSelectedWeek(p => p - 1);
  };

  const handleNextWeek = () => {
    if (selectedWeek < 42) setSelectedWeek(p => p + 1);
  };

  const handleResetToCurrent = () => {
    setSelectedWeek(calculations.currentWeek);
  };

  // Swipe Logic
  const touchStart = useRef<number | null>(null);
  const touchEnd = useRef<number | null>(null);
  const minSwipeDistance = 50;

  const onTouchStart = (e: React.TouchEvent) => {
    touchEnd.current = null;
    touchStart.current = e.targetTouches[0].clientX;
  };

  const onTouchMove = (e: React.TouchEvent) => {
    touchEnd.current = e.targetTouches[0].clientX;
  };

  const onTouchEnd = () => {
    if (!touchStart.current || !touchEnd.current) return;
    const distance = touchStart.current - touchEnd.current;
    const isLeftSwipe = distance > minSwipeDistance;
    const isRightSwipe = distance < -minSwipeDistance;

    if (isLeftSwipe) handleNextWeek();
    if (isRightSwipe) handlePrevWeek();
  };

  // --- RISK STRATIFICATION ENGINE (FOGSI / WHO) ---
  const calculateRiskProfile = () => {
      const risks: string[] = [];
      const actions: string[] = [];
      let level: 'Low' | 'Moderate' | 'High' = 'Low';

      // 1. Age
      const age = settings.age;
      if (age) {
          if (age < 18) {
              level = level === 'High' ? 'High' : 'Moderate';
              risks.push(MATERNAL_AGE_RISKS.teenage.label);
              actions.push(MATERNAL_AGE_RISKS.teenage.action);
          } else if (age > 35) {
              level = 'High';
              risks.push(MATERNAL_AGE_RISKS.advanced.label);
              actions.push(MATERNAL_AGE_RISKS.advanced.action);
          }
      }

      // 2. BMI
      if (settings.heightCm && settings.prePregnancyWeight) {
          const bmi = settings.prePregnancyWeight / ((settings.heightCm / 100) ** 2);
          if (bmi > 30) {
              level = 'High';
              risks.push("Obesity (BMI > 30)");
              actions.push("High risk of GDM/HTN. Early GTT required. Monitor fetal growth.");
          } else if (bmi < 18.5) {
              level = level === 'High' ? 'High' : 'Moderate';
              risks.push("Underweight");
              actions.push("Risk of IUGR (Small Baby). Increase caloric intake.");
          }
      }

      // 3. Comorbidities
      if (selectedComorbidities.length > 0) {
          level = 'High';
          // Actions handled by existing comorbidity logic in UI
      }

      // 4. Obstetric History
      const obs = settings.obstetricHistory;
      if (obs) {
          if (obs.abortionsT1 >= 2) {
              level = 'High';
              risks.push(OBSTETRIC_HISTORY_RISKS.recurrent_t1.label);
              actions.push(OBSTETRIC_HISTORY_RISKS.recurrent_t1.action);
          }
          if (obs.abortionsT2 >= 1) {
              level = 'High';
              risks.push(OBSTETRIC_HISTORY_RISKS.t2_loss.label);
              actions.push(OBSTETRIC_HISTORY_RISKS.t2_loss.action);
          }
          if (obs.lastBabyCongenitalDefect) {
              level = 'High';
              risks.push(OBSTETRIC_HISTORY_RISKS.prev_anomaly.label);
              actions.push(OBSTETRIC_HISTORY_RISKS.prev_anomaly.action);
          }
      }

      return { level, risks, actions };
  };

  const riskProfile = calculateRiskProfile();

  const isFuture = selectedWeek > calculations.currentWeek;
  const isPast = selectedWeek < calculations.currentWeek;

  const currentTip = DAILY_TIPS[selectedWeek.toString()] || DAILY_TIPS["default"];

  return (
    <div className="space-y-8 animate-fade-in pb-10">
      {/* Navigation Header if not on current week */}
      {(isFuture || isPast) && (
        <div className="flex justify-center -mb-4 z-10 relative">
          <button 
            onClick={handleResetToCurrent}
            className="flex items-center gap-2 px-4 py-2 bg-pink-100 dark:bg-pink-900/30 text-pink-700 dark:text-pink-300 rounded-full text-sm font-bold hover:bg-pink-200 transition-colors shadow-sm"
          >
            <RotateCcw size={14} /> Back to Current Week ({calculations.currentWeek})
          </button>
        </div>
      )}

      {/* Hero Section */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

        {/* Swipeable Progress Card */}
        <div 
            className="col-span-1 md:col-span-2 bg-gradient-to-br from-pink-600 to-purple-700 rounded-3xl p-6 text-white shadow-xl shadow-pink-500/20 relative overflow-hidden select-none"
            onTouchStart={onTouchStart}
            onTouchMove={onTouchMove}
            onTouchEnd={onTouchEnd}
        >
            <div className="absolute top-0 right-0 w-64 h-64 bg-white opacity-5 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl pointer-events-none"></div>

            {/* Desktop Arrows */}
            <button 
                onClick={handlePrevWeek}
                disabled={selectedWeek <= 1}
                className="absolute left-4 top-1/2 -translate-y-1/2 p-2 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-sm transition-all disabled:opacity-0 hidden md:block z-20"
            >
                <ChevronLeft size={24} />
            </button>
            <button 
                onClick={handleNextWeek}
                disabled={selectedWeek >= 42}
                className="absolute right-4 top-1/2 -translate-y-1/2 p-2 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-sm transition-all disabled:opacity-0 hidden md:block z-20"
            >
                <ChevronRight size={24} />
            </button>

            <div className="relative z-10 flex flex-col md:flex-row items-center gap-8 justify-center md:justify-start">
                <div className="relative w-40 h-40 flex-shrink-0">
                    <svg className="w-full h-full -rotate-90" viewBox="0 0 100 100">
                        <circle className="text-white/20 stroke-current" strokeWidth="8" cx="50" cy="50" r="40" fill="transparent"></circle>
                        <circle 
                            className="text-white stroke-current transition-all duration-500 ease-out" 
                            strokeWidth="8" 
                            strokeLinecap="round" 
                            cx="50" 
                            cy="50" 
                            r="40" 
                            fill="transparent" 
                            strokeDasharray="251.2" 
                            strokeDashoffset={251.2 - (251.2 * displayProgress) / 100}
                        ></circle>
                    </svg>
                    <div className="absolute top-0 left-0 w-full h-full flex flex-col items-center justify-center text-center">
                        <span className="text-4xl font-bold">{selectedWeek}</span>
                        <span className="text-sm font-medium opacity-80">
                           {selectedWeek === calculations.currentWeek ? `+ ${calculations.currentDay}d` : 'Weeks'}
                        </span>
                    </div>
                </div>

                <div className="text-center md:text-left space-y-2">
                    <div className="flex items-center justify-center md:justify-start gap-2">
                        {/* Mobile Arrows Inline */}
                        <button onClick={handlePrevWeek} className="md:hidden p-1 text-white/70 active:text-white"><ChevronLeft size={24} /></button>
                        <h2 className="text-2xl font-bold text-white">
                           {isFuture 
                               ? 'Future View' 
                               : isPast 
                                    ? 'Past View' 
                                    : `Week ${selectedWeek}, Day ${calculations.currentDay}`
                           }
                        </h2>
                        <button onClick={handleNextWeek} className="md:hidden p-1 text-white/70 active:text-white"><ChevronRight size={24} /></button>
                    </div>

                    <p className="text-lg text-white font-medium">Trimester {displayTrimester}</p>
                    <p className="opacity-90 text-white text-sm">
                        {isFuture 
                            ? `Previewing your journey for Week ${selectedWeek}` 
                            : `Estimated Due Date: ${calculations.edd.toDateString()}`
                        }
                    </p>

                    <div className="flex flex-wrap gap-2 justify-center md:justify-start mt-4">
                        <span className="px-3 py-1 bg-white/20 rounded-full text-xs backdrop-blur-md text-white">
                             Month {displayMonth}
                        </span>
                        {/* Risk Label */}
                        <span className={`px-3 py-1 rounded-full text-xs backdrop-blur-md text-white font-bold border border-white/20 ${riskProfile.level === 'High' ? 'bg-red-500/50' : riskProfile.level === 'Moderate' ? 'bg-yellow-500/50' : 'bg-green-500/30'}`}>
                            {riskProfile.level} Risk Profile
                        </span>
                    </div>
                </div>
            </div>

            <div className="md:hidden text-center mt-4 text-white/40 text-xs">
                Swipe left/right to navigate
            </div>
        </div>

        {/* Baby Size Card - Dynamic */}
        <div className="bg-white dark:bg-deep-card p-6 rounded-3xl shadow-lg border border-pink-100 dark:border-indigo-800 flex flex-col items-center justify-center text-center relative overflow-hidden transition-all duration-300">
             <div className="absolute inset-0 bg-gradient-to-tr from-yellow-50 to-orange-50 dark:from-yellow-900/10 dark:to-orange-900/10 opacity-50"></div>
             <div className="relative z-10 w-full animate-fade-in" key={selectedWeek}> 
                {/* Key forces re-render animation on week change */}
                <div className="w-20 h-20 bg-gradient-to-br from-yellow-400 to-orange-500 rounded-full mx-auto mb-4 flex items-center justify-center text-white shadow-lg">
                    <Baby size={40} />
                </div>
                <h3 className="text-gray-500 dark:text-gray-400 text-sm uppercase tracking-wider mb-1">
                    Week {selectedWeek} Size
                </h3>
                <p className="text-3xl font-bold text-gray-800 dark:text-white mb-2">{weekInfo.babySize}</p>
                <div className="flex justify-center gap-4 text-sm text-gray-600 dark:text-gray-300">
                    <div>
                        <span className="block font-bold">{weekInfo.babyWeight}</span>
                        <span className="text-xs">Avg Weight</span>
                    </div>
                    <div className="w-px bg-gray-300 dark:bg-gray-600"></div>
                    <div>
                        <span className="block font-bold">{weekInfo.babyLength}</span>
                        <span className="text-xs">Avg Length</span>
                    </div>
                </div>
             </div>
        </div>
      </div>

      {/* --- CLINICAL RISK PROFILE CARD (FOGSI) --- */}
      {(riskProfile.level !== 'Low' || riskProfile.actions.length > 0) && selectedWeek === calculations.currentWeek && (
          <div className={`rounded-3xl shadow-lg border p-6 ${riskProfile.level === 'High' ? 'bg-red-50 dark:bg-red-900/10 border-red-200 dark:border-red-900/30' : 'bg-yellow-50 dark:bg-yellow-900/10 border-yellow-200 dark:border-yellow-900/30'}`}>
              <div className="flex items-center gap-3 mb-3">
                  <ShieldAlert className={riskProfile.level === 'High' ? "text-red-600" : "text-yellow-600"} />
                  <h3 className={`text-lg font-bold ${riskProfile.level === 'High' ? "text-red-800 dark:text-red-200" : "text-yellow-800 dark:text-yellow-200"}`}>
                      Clinical Risk Assessment: {riskProfile.level} Risk
                  </h3>
              </div>

              <div className="space-y-4">
                  <div>
                      <p className="text-xs font-bold uppercase opacity-70 mb-1 text-gray-700 dark:text-gray-300">Detected Factors:</p>
                      <div className="flex flex-wrap gap-2">
                          {riskProfile.risks.length > 0 ? riskProfile.risks.map((r, i) => (
                              <span key={i} className="px-2 py-1 bg-white/50 dark:bg-black/20 rounded text-sm font-medium border border-black/5 dark:border-white/10 text-gray-800 dark:text-gray-200">
                                  {r}
                              </span>
                          )) : <span className="text-sm text-gray-500">Based on Comorbidities/History</span>}
                      </div>
                  </div>

                  {riskProfile.actions.length > 0 && (
                      <div className="bg-white/60 dark:bg-black/20 p-4 rounded-xl">
                          <p className="text-xs font-bold uppercase opacity-70 mb-2 text-gray-800 dark:text-white">Medical Recommendations (FOGSI/WHO):</p>
                          <ul className="list-disc list-inside space-y-1 text-sm text-gray-800 dark:text-gray-200 font-medium">
                              {riskProfile.actions.map((action, i) => (
                                  <li key={i}>{action}</li>
                              ))}
                          </ul>
                      </div>
                  )}

                  <p className="text-xs italic opacity-80 mt-2 text-gray-600 dark:text-gray-400 border-t border-gray-300 dark:border-gray-700 pt-2">
                      Disclaimer: This assessment is based on standard guidelines. Please discuss this risk profile with your gynecologist for a personalized care plan.
                  </p>
              </div>
          </div>
      )}

      {/* Alerts Section - Scans, Vaccines, Labs */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

          {relevantScans.length > 0 && (
             <div className="bg-orange-50 dark:bg-orange-900/10 p-4 rounded-3xl border border-orange-100 dark:border-orange-900/30 flex gap-4 items-center">
                <div className="bg-orange-100 dark:bg-orange-800/30 p-3 rounded-full text-orange-600 dark:text-orange-400 shrink-0">
                   <Bell className="w-6 h-6" />
                </div>
                <div className="flex-1">
                   <h3 className="font-bold text-orange-800 dark:text-orange-200 text-sm uppercase">Scan Due</h3>
                   <p className="text-orange-700 dark:text-orange-300 text-sm font-bold">
                      {relevantScans[0].name}
                   </p>
                   <p className="text-xs text-orange-600 dark:text-orange-400">Weeks {relevantScans[0].weekStart}-{relevantScans[0].weekEnd}</p>
                </div>
             </div>
          )}

          {relevantLabs.length > 0 && (
             <div className="bg-purple-50 dark:bg-purple-900/10 p-4 rounded-3xl border border-purple-100 dark:border-purple-900/30 flex gap-4 items-center">
                <div className="bg-purple-100 dark:bg-purple-800/30 p-3 rounded-full text-purple-600 dark:text-purple-400 shrink-0">
                   <FlaskConical className="w-6 h-6" />
                </div>
                <div className="flex-1">
                   <h3 className="font-bold text-purple-800 dark:text-purple-200 text-sm uppercase">Lab Test Recommended</h3>
                   <p className="text-purple-700 dark:text-purple-300 text-sm font-bold">
                      {relevantLabs[0].name}
                   </p>
                   {relevantLabs[0].condition && (
                       <span className="text-[10px] bg-purple-200 text-purple-800 px-1.5 py-0.5 rounded font-bold uppercase mt-1 inline-block">
                           {relevantLabs[0].condition.replace('_', ' ')}
                       </span>
                   )}
                </div>
             </div>
          )}

          {upcomingVaccines.length > 0 && (
             <div className="bg-teal-50 dark:bg-teal-900/10 p-4 rounded-3xl border border-teal-100 dark:border-teal-900/30 flex gap-4 items-center">
                <div className="bg-teal-100 dark:bg-teal-800/30 p-3 rounded-full text-teal-600 dark:text-teal-400 shrink-0">
                   <Syringe className="w-6 h-6" />
                </div>
                <div className="flex-1">
                   <h3 className="font-bold text-teal-800 dark:text-teal-200 text-sm uppercase">Vaccine Due</h3>
                   <p className="text-teal-700 dark:text-teal-300 text-sm font-bold">
                      {upcomingVaccines[0].name}
                   </p>
                   <p className="text-xs text-teal-600 dark:text-teal-400">Due: Week {upcomingVaccines[0].dueWeekStart}-{upcomingVaccines[0].dueWeekEnd}</p>
                </div>
             </div>
          )}
      </div>

      {/* Comorbidities Monitoring Plan (Always visible but contextual) */}
      {selectedComorbidities.length > 0 && selectedWeek === calculations.currentWeek && (
        <div className="bg-white dark:bg-deep-card rounded-3xl shadow-lg border border-pink-100 dark:border-indigo-800 overflow-hidden">
           <div className="bg-gradient-to-r from-purple-600 to-indigo-600 p-6 text-white">
              <h3 className="text-xl font-bold flex items-center gap-2">
                 <Activity size={24} /> Personalized Monitoring Plan
              </h3>
              <p className="opacity-80 text-sm mt-1">Based on your selected health conditions for THIS week.</p>
           </div>

           <div className="p-6 divide-y divide-gray-100 dark:divide-indigo-800">
              {selectedComorbidities.map(id => {
                const guide = COMORBIDITY_GUIDELINES[id];
                if(!guide) return null;
                return (
                   <div key={id} className="py-6 first:pt-0 last:pb-0">
                      <h4 className="font-bold text-lg text-purple-700 dark:text-purple-300 mb-3">{guide.name}</h4>

                      <div className="grid md:grid-cols-2 gap-4 mb-4">
                         <div className="bg-purple-50 dark:bg-purple-900/10 p-4 rounded-xl border border-purple-100 dark:border-purple-900/30">
                            <p className="text-xs font-bold text-purple-600 dark:text-purple-400 uppercase mb-1">Required Tests</p>
                            <ul className="list-disc list-inside text-sm text-gray-700 dark:text-gray-300">
                               {guide.tests.map((t, i) => <li key={i}>{t}</li>)}
                            </ul>
                            <p className="text-xs font-bold text-purple-600 dark:text-purple-400 uppercase mt-3 mb-1">Frequency</p>
                            <p className="text-sm font-medium text-gray-800 dark:text-white">{guide.frequency}</p>
                         </div>

                         <div className="bg-blue-50 dark:bg-blue-900/10 p-4 rounded-xl border border-blue-100 dark:border-blue-900/30">
                             <p className="text-xs font-bold text-blue-600 dark:text-blue-400 uppercase mb-1">How to Monitor</p>
                             <ul className="space-y-1">
                                {guide.monitoring.map((m, i) => (
                                   <li key={i} className="text-sm text-gray-700 dark:text-gray-300 flex items-start gap-2">
                                      <span className="mt-1.5 w-1 h-1 rounded-full bg-blue-400 shrink-0"></span> {m}
                                   </li>
                                ))}
                             </ul>
                         </div>
                      </div>

                      <div className="bg-red-50 dark:bg-red-900/10 p-3 rounded-lg border border-red-100 dark:border-red-900/30 flex items-start gap-3">
                          <AlertCircle size={18} className="text-red-500 shrink-0 mt-0.5" />
                          <div>
                             <span className="text-sm font-bold text-red-700 dark:text-red-400">Red Flags (Contact Doctor): </span>
                             <span className="text-sm text-red-600 dark:text-red-300">{guide.alertSigns.join(', ')}</span>
                          </div>
                      </div>
                   </div>
                );
              })}
           </div>
        </div>
      )}

      {/* Info Grid - Content updates based on selectedWeek */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Development */}
        <div className="lg:col-span-2 space-y-6">
            <div className="bg-white dark:bg-deep-card p-6 rounded-3xl shadow-lg border border-pink-100 dark:border-indigo-800" key={selectedWeek}>
                <h3 className="text-xl font-bold mb-4 flex items-center gap-2 text-gray-800 dark:text-white">
                    <Info className="text-pink-600" /> 
                    Week {selectedWeek} Highlights
                </h3>
                <p className="text-gray-600 dark:text-gray-300 leading-relaxed mb-4">
                    {weekInfo.description}
                </p>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-6">
                    <div className="bg-green-50 dark:bg-green-900/20 p-4 rounded-2xl border border-green-100 dark:border-green-800">
                        <h4 className="font-bold text-green-700 dark:text-green-400 mb-2">Do's</h4>
                        <ul className="list-disc list-inside space-y-1 text-sm text-gray-700 dark:text-gray-300">
                            {weekInfo.toDo.map((item, i) => <li key={i}>{item}</li>)}
                        </ul>
                    </div>
                    <div className="bg-red-50 dark:bg-red-900/20 p-4 rounded-2xl border border-red-100 dark:border-red-800">
                        <h4 className="font-bold text-red-700 dark:text-red-400 mb-2">Don'ts</h4>
                        <ul className="list-disc list-inside space-y-1 text-sm text-gray-700 dark:text-gray-300">
                            {weekInfo.notToDo.map((item, i) => <li key={i}>{item}</li>)}
                        </ul>
                    </div>
                </div>
            </div>

            {/* AI Advisor - Context Aware */}
            <div className="bg-gradient-to-r from-indigo-600 to-purple-600 rounded-3xl p-6 shadow-lg text-white">
                <h3 className="text-lg font-bold mb-2 flex items-center gap-2">
                    <Sparkles size={20} /> Ask Dr. Bloom AI
                </h3>
                <p className="text-sm opacity-80 mb-4">
                    Ask about symptoms, diet, or reports for Week {selectedWeek}.
                </p>

                <div className="flex gap-2 mb-4">
                    <input 
                        type="text" 
                        value={question}
                        onChange={(e) => setQuestion(e.target.value)}
                        placeholder="e.g. Is back pain normal this week?"
                        className="flex-1 px-4 py-2 rounded-xl text-gray-900 focus:outline-none"
                    />
                    <Button onClick={askAi} isLoading={loadingAi} className="bg-white text-indigo-700 hover:bg-gray-100">
                        Ask
                    </Button>
                </div>

                {aiAnswer && (
                    <div className="bg-white/10 backdrop-blur-md p-4 rounded-xl text-sm leading-relaxed border border-white/20 animate-fade-in">
                        {aiAnswer}
                    </div>
                )}
            </div>
        </div>

        {/* Sidebar Widgets */}
        <div className="space-y-6">
            <div className="bg-blue-50 dark:bg-blue-900/10 p-6 rounded-3xl border border-blue-100 dark:border-blue-900/30">
                <h4 className="font-bold text-blue-800 dark:text-blue-300 mb-2 flex items-center gap-2">
                    <Activity size={18} /> Daily Tip
                </h4>
                <p className="text-sm text-blue-700 dark:text-blue-400">
                    {currentTip}
                </p>
            </div>

            <div className="bg-white dark:bg-deep-card p-6 rounded-3xl shadow-lg border border-gray-100 dark:border-indigo-800">
                <h4 className="font-bold text-gray-800 dark:text-white mb-4">Common Symptoms</h4>
                <div className="flex flex-wrap gap-2">
                    {weekInfo.symptoms.map((sym, i) => (
                        <span key={i} className="px-3 py-1 bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-300 rounded-full text-xs font-bold">
                            {sym}
                        </span>
                    ))}
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { UserSettings } from '../types';
import { PRE_CONCEPTION_CHECKLIST, PRE_CONCEPTION_COMORBIDITY_GUIDELINES, OBSTETRIC_HISTORY_RISKS } from '../constants';
import { Button } from './Button';
import { Calendar, Droplet, Heart, CheckCircle2, Circle, AlertCircle, TrendingUp, Info, Plus, RotateCcw, X, Trash2, ChevronLeft, ChevronRight, Edit2, ShieldAlert, Check, Save, Star, Shield, Thermometer, TestTube2, Baby, ArrowRight, Gift, FileText, Activity } from 'lucide-react';

interface Props {
  settings: UserSettings;
  onUpdateSettings: (s: UserSettings) => void;
}

export const PrePregnancyDashboard: React.FC<Props> = ({ settings, onUpdateSettings }) => {
  const [completedTasks, setCompletedTasks] = useState<string[]>(settings.preConceptionChecklist || []);
  const [cycleDay, setCycleDay] = useState(1);
  const [daysUntilPeriod, setDaysUntilPeriod] = useState(0);
  const [conceptionChance, setConceptionChance] = useState<string>('');

  // Modals
  const [showLogModal, setShowLogModal] = useState(false); // For "Add Past Date"
  const [showHistoryModal, setShowHistoryModal] = useState(false); // For "Manage History"
  const [showConfirmStart, setShowConfirmStart] = useState(false); // For "Log Period Start" (Today)
  const [showPregnancyModal, setShowPregnancyModal] = useState(false); // For Switching Mode

  const [newPastDate, setNewPastDate] = useState('');

  // Editing State
  const [editingDate, setEditingDate] = useState<string | null>(null);
  const [editValue, setEditValue] = useState<string>('');

  // Calendar State
  const [calendarDate, setCalendarDate] = useState(new Date());

  // Helper: Parse YYYY-MM-DD to local midnight Date object
  const parseLocalYMD = (dateString: string) => {
      if (!dateString) return new Date();
      const [y, m, d] = dateString.split('-').map(Number);
      return new Date(y, m - 1, d);
  };

  // Helper: Format Date to YYYY-MM-DD local
  const formatLocalYMD = (date: Date) => {
      const year = date.getFullYear();
      const month = String(date.getMonth() + 1).padStart(2, '0');
      const day = String(date.getDate()).padStart(2, '0');
      return `${year}-${month}-${day}`;
  };

  // Helper: Get Fertility Probability & Phase Info
  const getCyclePhaseInfo = (currentDay: number, cycleLen: number, isLog: boolean) => {
      const ovulationDay = cycleLen - 14;
      const fertileStart = ovulationDay - 5;
      const fertileEnd = ovulationDay + 2;
      const diff = ovulationDay - currentDay;

      // 1. Period Phase (Actual Log)
      if (isLog) {
          return {
              phase: 'Period_Log',
              label: 'Menstruation',
              subLabel: 'Cycle Restart',
              gradient: 'from-rose-600 to-red-700',
              shadow: 'shadow-rose-600/30',
              colorClass: 'bg-rose-600',
              textClass: 'text-white',
              icon: Droplet,
              chance: '<1%'
          };
      }

      // 2. Period Phase (Expected)
      if (currentDay >= 1 && currentDay <= 5) {
          return {
              phase: 'Period_Exp',
              label: 'Expected Period',
              subLabel: 'Predicted',
              gradient: 'from-rose-400 to-rose-500',
              shadow: 'shadow-rose-400/30',
              colorClass: 'bg-rose-300 dark:bg-rose-900/60', // Lighter/Distinct
              textClass: 'text-rose-900 dark:text-rose-100',
              icon: Droplet,
              chance: '<1%'
          };
      }

      // 3. Ovulation (Peak)
      if (currentDay === ovulationDay) {
          return {
              phase: 'Ovulation',
              label: 'Ovulation Day',
              subLabel: 'Egg Release',
              gradient: 'from-purple-600 to-fuchsia-600',
              shadow: 'shadow-purple-500/30',
              colorClass: 'bg-purple-600',
              textClass: 'text-white',
              icon: Star,
              chance: '33%'
          };
      }

      // 4. Fertile Window
      if (currentDay >= fertileStart && currentDay <= fertileEnd) {
          // High Fertility (1-2 days before O)
          if (diff === 1 || diff === 2) {
              return {
                  phase: 'High',
                  label: 'High Fertility',
                  subLabel: 'Best Time to Try',
                  gradient: 'from-emerald-500 to-green-600',
                  shadow: 'shadow-emerald-500/30',
                  colorClass: 'bg-emerald-500',
                  textClass: 'text-white',
                  icon: Heart,
                  chance: diff === 1 ? '31%' : '27%'
              };
          }
          // Medium/Start of Window
          return {
              phase: 'Fertile',
              label: 'Fertile Window',
              subLabel: 'Good Chance',
              gradient: 'from-teal-400 to-teal-600',
              shadow: 'shadow-teal-500/30',
              colorClass: 'bg-teal-500',
              textClass: 'text-white',
              icon: TrendingUp,
              chance: diff > 2 ? '15-17%' : '10%'
          };
      }

      // 5. Safe / Luteal
      return {
          phase: 'Safe',
          label: 'Luteal Phase',
          subLabel: 'Low Fertility',
          gradient: 'from-blue-500 to-indigo-600',
          shadow: 'shadow-blue-500/30',
          colorClass: 'bg-blue-100 dark:bg-blue-900/50',
          textClass: 'text-blue-900 dark:text-blue-100', 
          icon: Shield,
          chance: '<1%'
      };
  };

  // --- Cycle Calculations (Medical Standard: WHO / FOGSI) ---
  useEffect(() => {
    if (settings.lmp) {
      const lmpDate = parseLocalYMD(settings.lmp);
      const today = new Date();
      today.setHours(0,0,0,0);

      const diffTime = today.getTime() - lmpDate.getTime();
      const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));

      // Let's use linear day for display and logic
      const linearCycleDay = diffDays + 1;
      setCycleDay(linearCycleDay);

      // Determine chance for today
      const todayLog = (settings.periodLog || []).includes(formatLocalYMD(today));
      // For phase coloring we wrap around cycle length
      const wrappedCycleDay = ((diffDays % settings.cycleLength) + settings.cycleLength) % settings.cycleLength + 1;

      const phase = getCyclePhaseInfo(wrappedCycleDay, settings.cycleLength, todayLog);
      setConceptionChance(phase.chance);

      setDaysUntilPeriod(settings.cycleLength - linearCycleDay + 1);
    }
  }, [settings.lmp, settings.cycleLength, settings.periodLog]);

  // --- CLINICAL CYCLE ANALYSIS ALGORITHM (FOGSI/FIGO Standards) ---
  const analyzeCycleHealth = () => {
      const logs = settings.periodLog || [];
      if (logs.length < 2) {
          return { status: 'Insufficient Data', color: 'gray', advice: 'Log at least 3 periods for an accurate clinical assessment.', causes: [] };
      }

      // 1. Calculate lengths between consecutive periods
      const sortedDates = [...logs].map(d => parseLocalYMD(d)).sort((a, b) => a.getTime() - b.getTime());
      const lengths = [];
      for (let i = 0; i < sortedDates.length - 1; i++) {
          const diff = Math.ceil((sortedDates[i+1].getTime() - sortedDates[i].getTime()) / (1000 * 60 * 60 * 24));
          lengths.push(diff);
      }

      // If only 1 length available, we can only judge length, not regularity
      const avgLength = Math.round(lengths.reduce((a, b) => a + b, 0) / lengths.length);
      const minLength = Math.min(...lengths);
      const maxLength = Math.max(...lengths);
      const variation = maxLength - minLength;

      // --- CRITERIA 1: LENGTH (Normal 21-35 Days) ---
      if (avgLength < 21) {
          return {
              status: 'Polymenorrhea (Frequent Cycles)',
              color: 'red',
              advice: 'Your average cycle is shorter than 21 days. This may affect egg quality.',
              causes: ['Luteal Phase Defect', 'Anovulation', 'Stress', 'Perimenopause (if age > 35)']
          };
      }
      if (avgLength > 35) {
          return {
              status: 'Oligomenorrhea (Long Cycles)',
              color: 'red',
              advice: 'Your average cycle is longer than 35 days. This strongly suggests delayed ovulation.',
              causes: ['PCOS (Polycystic Ovarian Syndrome)', 'Thyroid Disorders', 'Hyperprolactinemia']
          };
      }

      // --- CRITERIA 2: REGULARITY (Variation < 7-9 days) ---
      // We need at least 3 logs (2 intervals) to judge regularity properly
      if (lengths.length >= 2) {
          if (variation >= 9) {
              return {
                  status: 'Irregular Cycles',
                  color: 'orange',
                  advice: `Your cycle varies by ${variation} days. This makes predicting ovulation difficult.`,
                  causes: ['Hormonal Imbalance', 'PCOS', 'Stress/Lifestyle', 'Thyroid issues']
              };
          }
      }

      return {
          status: 'Normal & Regular',
          color: 'green',
          advice: `Your cycle is consistent (${avgLength} days) and within the normal fertility range (21-35 days).`,
          causes: []
      };
  };

  const cycleAnalysis = analyzeCycleHealth();

  const toggleTask = (taskId: string) => {
      let updated;
      if (completedTasks.includes(taskId)) {
          updated = completedTasks.filter(id => id !== taskId);
      } else {
          updated = [...completedTasks, taskId];
      }
      setCompletedTasks(updated);
      onUpdateSettings({ ...settings, preConceptionChecklist: updated });
  };

  const handleLogPeriodToday = () => {
      const todayLocal = formatLocalYMD(new Date());
      const updatedLog = [todayLocal, ...(settings.periodLog || [])];
      const uniqueLog = [...new Set(updatedLog)].sort((a, b) => new Date(b).getTime() - new Date(a).getTime());

      onUpdateSettings({ 
          ...settings, 
          lmp: todayLocal, 
          periodLog: uniqueLog
      });
      setShowConfirmStart(false);
  };

  const toggleIntercourse = (dateStr: string) => {
      const currentLog = settings.intercourseLog || [];
      let updatedLog;
      if (currentLog.includes(dateStr)) {
          updatedLog = currentLog.filter(d => d !== dateStr);
      } else {
          updatedLog = [...currentLog, dateStr];
      }
      onUpdateSettings({ ...settings, intercourseLog: updatedLog });
  };

  const handleAddPastPeriod = () => {
      if(!newPastDate) return;
      const updatedLog = [newPastDate, ...(settings.periodLog || [])];
      const uniqueLog = [...new Set(updatedLog)].sort((a, b) => new Date(b).getTime() - new Date(a).getTime());

      let newLmp = settings.lmp;
      if (!newLmp || new Date(newPastDate) > new Date(newLmp)) {
          newLmp = newPastDate;
      }

      onUpdateSettings({
          ...settings,
          lmp: newLmp,
          periodLog: uniqueLog
      });
      setShowLogModal(false);
      setNewPastDate('');
  };

  const handleStartEdit = (date: string) => {
      setEditingDate(date);
      setEditValue(date);
  };

  const handleCancelEdit = () => {
      setEditingDate(null);
      setEditValue('');
  };

  const handleSaveEdit = () => {
      if (!editValue || !editingDate) return;
      const currentLog = settings.periodLog || [];
      let newLog = currentLog.filter(d => d !== editingDate && d !== editValue);
      newLog.push(editValue);
      newLog.sort((a, b) => new Date(b).getTime() - new Date(a).getTime());
      const newLmp = newLog.length > 0 ? newLog[0] : null;
      onUpdateSettings({ ...settings, periodLog: newLog, lmp: newLmp });
      setEditingDate(null);
      setEditValue('');
  };

  const handleDeleteLog = (dateToDelete: string, e?: React.MouseEvent) => {
      e?.preventDefault();
      e?.stopPropagation();
      if (!window.confirm("Are you sure you want to delete this period entry?")) return;
      const currentLog = settings.periodLog || [];
      const updatedLog = currentLog.filter(d => d !== dateToDelete);
      let newLmp = settings.lmp;
      if (dateToDelete === settings.lmp || !updatedLog.includes(settings.lmp || '')) {
          const sorted = [...updatedLog].sort((a, b) => new Date(b).getTime() - new Date(a).getTime());
          newLmp = sorted.length > 0 ? sorted[0] : null;
      }
      onUpdateSettings({ ...settings, lmp: newLmp, periodLog: updatedLog });
  };

  const handleSwitchToPregnancy = () => {
      setShowPregnancyModal(true);
  };

  const confirmPregnancySwitch = () => {
      onUpdateSettings({
          ...settings,
          status: 'pregnant',
          isPostpartum: false,
          pregnancyLmp: settings.lmp
      });
      setShowPregnancyModal(false);
  };

  const calculatePredictedCycle = () => {
      const logs = settings.periodLog || [];
      if (logs.length < 2) return null;
      const sorted = [...logs].sort((a, b) => new Date(a).getTime() - new Date(b).getTime()); // Older first
      // Use logic above in analyzer, simplified here
      const recentLogs = sorted.slice(-7); 
      let totalDiff = 0;
      let count = 0;
      for(let i = 0; i < recentLogs.length - 1; i++) {
          const d1 = parseLocalYMD(recentLogs[i]);
          const d2 = parseLocalYMD(recentLogs[i+1]);
          const diffTime = Math.abs(d2.getTime() - d1.getTime());
          const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
          if(diffDays > 15 && diffDays < 50) {
              totalDiff += diffDays;
              count++;
          }
      }
      if(count === 0) return null;
      return Math.round(totalDiff / count);
  };

  const predictedCycle = calculatePredictedCycle();

  const applyPredictedCycle = () => {
      if(predictedCycle) {
          onUpdateSettings({ ...settings, cycleLength: predictedCycle });
      }
  };

  const calculateBMI = () => {
      if(settings.prePregnancyWeight && settings.heightCm) {
          const hM = settings.heightCm / 100;
          return (settings.prePregnancyWeight / (hM * hM)).toFixed(1);
      }
      return null;
  };

  const bmi = calculateBMI();
  let bmiStatus = { label: 'Unknown', color: 'text-gray-500', advice: '' };
  if(bmi) {
      const val = parseFloat(bmi);
      if(val < 18.5) bmiStatus = { label: 'Underweight', color: 'text-yellow-600', advice: 'Aim to gain a little weight to support ovulation.' };
      else if(val < 25) bmiStatus = { label: 'Normal Weight', color: 'text-green-600', advice: 'Great! Maintain this for optimal fertility.' };
      else if(val < 30) bmiStatus = { label: 'Overweight', color: 'text-orange-600', advice: 'Losing 5-10% weight can significantly boost fertility (PCOS).' };
      else bmiStatus = { label: 'Obese', color: 'text-red-600', advice: 'Consult a doctor for a safe weight loss plan before conceiving.' };
  }

  // --- Two-Week Wait / Conception Analysis Logic ---
  const analyzeConceptionPotential = () => {
      if (!settings.lmp) return null;
      const lmpDate = parseLocalYMD(settings.lmp);
      const today = new Date();
      today.setHours(0,0,0,0);

      // Current cycle logic
      const diffTime = today.getTime() - lmpDate.getTime();
      const currentCycleDays = Math.floor(diffTime / (1000 * 60 * 60 * 24)) + 1; // 1-based

      const ovulationDay = settings.cycleLength - 14;
      const fertileStart = ovulationDay - 5;
      const fertileEnd = ovulationDay + 2;

      // Only relevant if we are PAST ovulation (Luteal Phase) and BEFORE next period (or just missed)
      // Check 1 week post ovulation onwards
      if (currentCycleDays > ovulationDay + 7) {

          // Check if intercourse happened during fertile window of THIS cycle
          const logs = settings.intercourseLog || [];
          let hitFertileWindow = false;

          for (let d = fertileStart; d <= fertileEnd; d++) {
              const checkDate = new Date(lmpDate);
              checkDate.setDate(checkDate.getDate() + (d - 1)); // 0-based add
              const dateStr = formatLocalYMD(checkDate);
              if (logs.includes(dateStr)) {
                  hitFertileWindow = true;
                  break;
              }
          }

          if (hitFertileWindow) {
              const nextPeriodDate = new Date(lmpDate);
              nextPeriodDate.setDate(nextPeriodDate.getDate() + settings.cycleLength);
              const testDate = new Date(nextPeriodDate);
              testDate.setDate(testDate.getDate() + 1); // Test 1 day after missed period

              return {
                  status: 'potential',
                  testDate: testDate,
                  daysPostOvulation: currentCycleDays - ovulationDay
              };
          }
      }
      return null;
  };

  const conceptionStatus = analyzeConceptionPotential();
  const daysLate = cycleDay > settings.cycleLength ? cycleDay - settings.cycleLength : 0;

  // --- Calendar Logic ---
  const renderCalendar = () => {
      const year = calendarDate.getFullYear();
      const month = calendarDate.getMonth();
      const firstDay = new Date(year, month, 1);
      const lastDay = new Date(year, month + 1, 0);
      const daysInMonth = lastDay.getDate();
      const startDayOfWeek = firstDay.getDay(); 

      const calendarDays = [];
      for (let i = 0; i < startDayOfWeek; i++) {
          calendarDays.push(<div key={`empty-${i}`} className="h-10 md:h-14"></div>);
      }

      const lmpDate = settings.lmp ? parseLocalYMD(settings.lmp) : null;
      const cycleLen = settings.cycleLength;

      for (let d = 1; d <= daysInMonth; d++) {
          const currentDayStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
          const currentDayDate = new Date(year, month, d);

          const isActualLog = (settings.periodLog || []).includes(currentDayStr);
          const isIntercourse = (settings.intercourseLog || []).includes(currentDayStr);

          let phaseInfo = null;

          if (lmpDate) {
              const diffTime = currentDayDate.getTime() - lmpDate.getTime();
              const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
              // Handle future/past cycles relative to LMP
              const rawCycleDay = ((diffDays % cycleLen) + cycleLen) % cycleLen;
              const cycleDayNum = rawCycleDay + 1;

              phaseInfo = getCyclePhaseInfo(cycleDayNum, cycleLen, isActualLog);
          }

          let bgClass = phaseInfo ? phaseInfo.colorClass : "bg-gray-50 dark:bg-white/5";
          let textClass = phaseInfo ? phaseInfo.textClass : "text-gray-700 dark:text-gray-300";
          let borderClass = "border-transparent";

          if (phaseInfo) {
              if (phaseInfo.phase === 'Period_Log') {
                  textClass = "text-white font-bold";
              }
          }

          if (isIntercourse) {
              borderClass = "border-pink-400";
          }

          calendarDays.push(
              <button 
                key={d} 
                onClick={() => toggleIntercourse(currentDayStr)}
                className={`h-12 md:h-16 rounded-lg flex flex-col items-center justify-center text-xs md:text-sm relative transition-all border ${borderClass} ${bgClass} ${currentDayStr === formatLocalYMD(new Date()) ? 'ring-2 ring-pink-500 z-10 shadow-lg' : 'hover:opacity-80'}`}
              >
                  <span className={textClass + " font-bold"}>{d}</span>
                  {isActualLog && <div className="w-1.5 h-1.5 bg-white rounded-full mt-1"></div>}

                  {/* Phase Info */}
                  {phaseInfo && phaseInfo.chance !== '<1%' && !isActualLog && (
                      <span className={`text-[8px] md:text-[10px] uppercase font-bold mt-0.5 ${textClass}`}>
                          {phaseInfo.chance}
                      </span>
                  )}

                  {/* Intercourse Marker */}
                  {isIntercourse && (
                      <Heart size={12} className="fill-pink-500 text-pink-500 absolute top-1 right-1 animate-pulse" />
                  )}

                  {/* Ovulation Star */}
                  {phaseInfo?.phase === 'Ovulation' && !isIntercourse && (
                      <Star size={10} className="fill-yellow-400 text-yellow-400 absolute top-1 right-1" />
                  )}
              </button>
          );
      }

      return (
          <div className="space-y-4">
              <div className="flex items-center justify-between">
                  <h4 className="font-bold text-lg text-gray-800 dark:text-white">
                      {calendarDate.toLocaleString('default', { month: 'long', year: 'numeric' })}
                  </h4>
                  <div className="flex gap-2">
                      <button onClick={() => setCalendarDate(new Date(calendarDate.setMonth(calendarDate.getMonth() - 1)))} className="p-2 hover:bg-gray-100 dark:hover:bg-white/10 rounded-full"><ChevronLeft size={20} /></button>
                      <button onClick={() => setCalendarDate(new Date())} className="text-xs font-bold text-pink-600 px-2">Today</button>
                      <button onClick={() => setCalendarDate(new Date(calendarDate.setMonth(calendarDate.getMonth() + 1)))} className="p-2 hover:bg-gray-100 dark:hover:bg-white/10 rounded-full"><ChevronRight size={20} /></button>
                  </div>
              </div>
              <div className="grid grid-cols-7 gap-1 md:gap-2 text-center">
                  {['S','M','T','W','T','F','S'].map((day, i) => (
                      <div key={i} className="text-xs font-bold text-gray-400 py-1">{day}</div>
                  ))}
                  {calendarDays}
              </div>

              {/* Enhanced Legend */}
              <div className="flex flex-wrap gap-3 text-xs justify-center pt-2 bg-gray-50 dark:bg-indigo-900/10 p-3 rounded-xl border border-gray-100 dark:border-indigo-900/30">
                  <div className="flex items-center gap-1"><div className="w-3 h-3 bg-rose-600 rounded"></div> Period (Log)</div>
                  <div className="flex items-center gap-1"><div className="w-3 h-3 bg-purple-600 rounded"></div> Ovulation</div>
                  <div className="flex items-center gap-1"><div className="w-3 h-3 bg-emerald-500 rounded"></div> High Fertility</div>
                  <div className="flex items-center gap-1"><div className="w-3 h-3 bg-teal-500 rounded"></div> Fertile</div>
                  <div className="flex items-center gap-1"><Heart size={10} className="fill-pink-500 text-pink-500"/> Activity</div>
              </div>
          </div>
      );
  };

  const wrappedCycleDay = ((cycleDay - 1) % settings.cycleLength) + 1; // Wrap for color logic
  const currentPhaseInfo = getCyclePhaseInfo(wrappedCycleDay, settings.cycleLength, (settings.periodLog || []).includes(formatLocalYMD(new Date())));
  const isTodayIntercourse = (settings.intercourseLog || []).includes(formatLocalYMD(new Date()));

  // --- High Risk History Check ---
  const hasHistoryRisk = settings.obstetricHistory?.lastBabyCongenitalDefect || 
                         settings.obstetricHistory?.abortionsT1 >= 2 || 
                         settings.obstetricHistory?.abortionsT2 >= 1;

  return (
    <div className="space-y-8 animate-fade-in pb-10">

      {/* Missed Period Alert & Mode Switcher */}
      {daysLate > 0 && (
          <div className="bg-gradient-to-r from-pink-500 to-rose-500 rounded-3xl p-6 text-white shadow-xl animate-pulse-slow">
              <div className="flex flex-col md:flex-row items-start gap-4">
                  <div className="p-3 bg-white/20 rounded-full shrink-0">
                      <Baby size={32} />
                  </div>
                  <div className="flex-1">
                      <h3 className="text-xl font-bold">Period Late by {daysLate} Days?</h3>
                      <p className="opacity-90 text-sm mt-1">
                          If your home pregnancy test is positive, congratulations! You can switch modes now to start tracking your baby's journey.
                      </p>

                      <div className="bg-white/10 rounded-xl p-4 mt-3 text-xs space-y-2 border border-white/20">
                          <p className="font-bold uppercase opacity-80 flex items-center gap-2"><Gift size={12}/> Pregnancy Mode Benefits:</p>
                          <ul className="grid grid-cols-1 md:grid-cols-2 gap-1 opacity-90">
                              <li className="flex items-center gap-1"><CheckCircle2 size={10}/> Weekly Baby Growth (Size & Weight)</li>
                              <li className="flex items-center gap-1"><CheckCircle2 size={10}/> Trimester-Specific Diet Plans</li>
                              <li className="flex items-center gap-1"><CheckCircle2 size={10}/> Medical Scan & Vaccine Schedule</li>
                              <li className="flex items-center gap-1"><CheckCircle2 size={10}/> Contraction Timer & Kick Counter</li>
                          </ul>
                      </div>

                      <button 
                          onClick={handleSwitchToPregnancy}
                          className="mt-4 w-full py-3 bg-white text-pink-600 font-bold rounded-xl shadow-lg hover:bg-pink-50 transition-colors flex items-center justify-center gap-2"
                      >
                          <CheckCircle2 size={18} /> Yes, I'm Pregnant! Switch Mode
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* Hero: Cycle Status */}
      <div className={`rounded-3xl p-8 text-white shadow-xl relative overflow-hidden transition-all duration-500 bg-gradient-to-br ${currentPhaseInfo.gradient} ${currentPhaseInfo.shadow}`}>
         <div className="absolute top-0 right-0 w-64 h-64 bg-white opacity-10 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl pointer-events-none"></div>

         <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-6">
            <div className="text-center md:text-left">
                <div className="flex items-center justify-center md:justify-start gap-2 mb-2 opacity-90">
                    <Calendar size={20} />
                    <span className="text-sm font-bold uppercase tracking-wider">Cycle Day {cycleDay}</span>
                </div>
                <h2 className="text-4xl font-bold mb-2">
                    {daysLate > 0 ? "Period Missed" : currentPhaseInfo.label}
                </h2>
                <p className="text-lg opacity-90">
                    {daysLate > 0 
                        ? `${daysLate} days past expected date.`
                        : currentPhaseInfo.phase === 'Safe' 
                            ? `Next period in approx ${daysUntilPeriod} days.`
                            : `Conception Chance: ${currentPhaseInfo.chance}`
                    }
                </p>

                {currentPhaseInfo.phase !== 'Safe' && !currentPhaseInfo.phase.startsWith('Period') && daysLate <= 0 && (
                    <div className="mt-4 inline-flex items-center gap-2 bg-white/20 backdrop-blur-md px-4 py-2 rounded-full border border-white/20">
                        <currentPhaseInfo.icon size={16} fill="white" className="animate-pulse" />
                        <span className="font-bold text-sm">
                            {currentPhaseInfo.subLabel}
                        </span>
                    </div>
                )}
            </div>

            <div className="flex flex-col gap-3 w-full md:w-auto">
                <button 
                    onClick={() => toggleIntercourse(formatLocalYMD(new Date()))}
                    className={`group relative px-8 py-3 font-bold rounded-2xl shadow-lg transition-all flex items-center justify-center gap-3 overflow-hidden ${isTodayIntercourse ? 'bg-pink-100 text-pink-700' : 'bg-white text-gray-800'}`}
                >
                    <Heart size={20} className={isTodayIntercourse ? "fill-pink-600 text-pink-600" : "text-gray-400"} />
                    <span className="relative z-10">{isTodayIntercourse ? 'Activity Logged' : 'Log Activity'}</span>
