import React, { useState, useEffect, useMemo } from 'react';
import { UserSettings, PregnancyCalculations, TabView, ProfileMeta } from './types';
import { Onboarding } from './components/Onboarding';
import { Dashboard } from './components/Dashboard';
import { PostpartumDashboard } from './components/PostpartumDashboard';
import { PrePregnancyDashboard } from './components/PrePregnancyDashboard';
import { Timeline } from './components/Timeline';
import { ReportAnalyzer } from './components/ReportAnalyzer';
import { MedicineTracker } from './components/MedicineTracker';
import { Profile } from './components/Profile';
import { DietPlan } from './components/DietPlan';
import { VaccinationTracker } from './components/VaccinationTracker';
import { ToolsHub } from './components/ToolsHub';
import { HealthTracker } from './components/HealthTracker';
import { Login } from './components/Login';
import { LayoutDashboard, Calendar, FileText, Pill, Moon, Sun, Settings, User, Utensils, Syringe, Baby, Wrench, HeartPulse, LogOut, Users, PlusCircle } from 'lucide-react';

// Keys that store profile-specific data which need to be swapped on profile switch
const PROFILE_SPECIFIC_KEYS = [
  'bloom_kicks',
  'bloom_contractions',
  'bloom_milestones',
  'bloom_weight_logs',
  'bloom_pp_weight_logs',
  'bloom_bp_logs',
  'bloom_pp_bp_logs',
  'bloom_glucose_logs',
  'bloom_pp_glucose_logs',
  'bloom_baby_growth',
  'bloom_tsh_logs', 'bloom_pp_tsh_logs',
  'bloom_hb_logs', 'bloom_pp_hb_logs',
  'bloom_hba1c_logs', 'bloom_pp_hba1c_logs'
];

export default function App() {
  const [darkMode, setDarkMode] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [settings, setSettings] = useState<UserSettings | null>(null);
  const [activeTab, setActiveTab] = useState<TabView>(TabView.DASHBOARD);

  // Profile Management State
  const [profiles, setProfiles] = useState<ProfileMeta[]>([]);
  const [showProfileSwitcher, setShowProfileSwitcher] = useState(false);

  // Load auth & settings & profile meta
  useEffect(() => {
    const auth = localStorage.getItem('bloom_auth');
    if (auth === 'true') {
      setIsAuthenticated(true);
    }

    const savedSettings = localStorage.getItem('bloom_settings');
    const savedProfiles = localStorage.getItem('bloom_all_profiles');

    if (savedSettings) {
      const parsed = JSON.parse(savedSettings);

      // Legacy Migration: If no ID, assign one and create profile meta
      if (!parsed.id) {
          parsed.id = 'default_profile_' + Date.now();
          localStorage.setItem('bloom_settings', JSON.stringify(parsed));
      }

      // Default field migrations for older data
      if (!parsed.status) parsed.status = parsed.isPostpartum ? 'postpartum' : 'pregnant';
      if (!parsed.comorbidities) parsed.comorbidities = [];
      if (!parsed.dietaryPreference) parsed.dietaryPreference = 'vegetarian';
      if (parsed.lactoseIntolerant === undefined) parsed.lactoseIntolerant = false;
      if (!parsed.vaccinationsDone) parsed.vaccinationsDone = [];
      if (!parsed.preConceptionChecklist) parsed.preConceptionChecklist = [];
      if (!parsed.periodLog) parsed.periodLog = [];
      if (parsed.pregnancyLmp === undefined) parsed.pregnancyLmp = null;
      if (!parsed.maternalBloodGroup) parsed.maternalBloodGroup = '';

      // Migration for new Risk Features (Obstetric History & Age)
      if (!parsed.obstetricHistory) {
          parsed.obstetricHistory = {
              gravida: 1,
              para: 0,
              abortions: 0,
              abortionsT1: 0,
              abortionsT2: 0,
              living: 0,
              lastBabyCongenitalDefect: false
          };
      }
      if (parsed.age === undefined) parsed.age = 0; 

      setSettings(parsed);

      // Initialize Profiles List
      if (savedProfiles) {
          setProfiles(JSON.parse(savedProfiles));
      } else {
          // Create initial profile list from current settings
          const initialProfile: ProfileMeta = {
              id: parsed.id,
              name: parsed.name,
              status: parsed.status,
              babyName: parsed.babyName,
              babyGender: parsed.babyGender,
              birthDate: parsed.birthDate,
              lastActive: new Date().toISOString()
          };
          setProfiles([initialProfile]);
          localStorage.setItem('bloom_all_profiles', JSON.stringify([initialProfile]));
      }
    }
  }, []);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  // --- Profile Switching Logic ---

  const handleSwitchProfile = (targetProfileId: string) => {
      if (!settings || settings.id === targetProfileId) return;

      // 1. Snapshot Current Profile Data
      // Save current active logs into namespaced keys (e.g. bloom_kicks_profile_1)
      PROFILE_SPECIFIC_KEYS.forEach(key => {
          const data = localStorage.getItem(key);
          if (data) {
              localStorage.setItem(`${key}_${settings.id}`, data);
          } else {
              localStorage.removeItem(`${key}_${settings.id}`);
          }
      });
      // Save current settings to namespaced key
      localStorage.setItem(`bloom_settings_${settings.id}`, JSON.stringify(settings));

      // 2. Hydrate Target Profile Data
      // Load target profile logs into active keys
      PROFILE_SPECIFIC_KEYS.forEach(key => {
          const savedData = localStorage.getItem(`${key}_${targetProfileId}`);
          if (savedData) {
              localStorage.setItem(key, savedData);
          } else {
              localStorage.removeItem(key); // Clear if no data for target
          }
      });

      // 3. Load Target Settings
      const targetSettingsRaw = localStorage.getItem(`bloom_settings_${targetProfileId}`);
      if (targetSettingsRaw) {
          const targetSettings = JSON.parse(targetSettingsRaw);
          setSettings(targetSettings);
          localStorage.setItem('bloom_settings', targetSettingsRaw); // Set as active settings

          // Update Meta Last Active
          const updatedProfiles = profiles.map(p => 
              p.id === targetProfileId ? { ...p, lastActive: new Date().toISOString() } : p
          );
          setProfiles(updatedProfiles);
          localStorage.setItem('bloom_all_profiles', JSON.stringify(updatedProfiles));

          // Refresh to ensure all sub-components read new localStorage values
          window.location.reload(); 
      }
  };

  const handleAddProfile = () => {
      if (!settings) return;

      // 1. Snapshot Current Data (Same as switch)
      PROFILE_SPECIFIC_KEYS.forEach(key => {
          const data = localStorage.getItem(key);
          if (data) localStorage.setItem(`${key}_${settings.id}`, data);
          else localStorage.removeItem(`${key}_${settings.id}`);
      });
      localStorage.setItem(`bloom_settings_${settings.id}`, JSON.stringify(settings));

      // 2. Create New Settings (Inherit Shared Data)
      const newId = `profile_${Date.now()}`;
      const newSettings: UserSettings = {
          id: newId,
          name: settings.name, // Mom's name is shared
          status: 'planning', // Default to planning for new journey
          lmp: null,
          cycleLength: settings.cycleLength,

          // Shared Stats (Don't make mom re-enter)
          heightCm: settings.heightCm,
          prePregnancyWeight: settings.prePregnancyWeight, // Might change, but good default
          maternalBloodGroup: settings.maternalBloodGroup,
          paternalBloodGroup: settings.paternalBloodGroup,
          paternalHeightCm: settings.paternalHeightCm,
          obstetricHistory: settings.obstetricHistory, // Copy history
          comorbidities: settings.comorbidities, // Usually persistent
          dietaryPreference: settings.dietaryPreference,
          lactoseIntolerant: settings.lactoseIntolerant,
          age: settings.age,

          // Reset Logs for new baby
          periodLog: [],
          vaccinationsDone: [],
          isPostpartum: false,
          preConceptionChecklist: []
      };

      // 3. Clear Active Keys for fresh start
      PROFILE_SPECIFIC_KEYS.forEach(key => localStorage.removeItem(key));

      // 4. Update State & Storage
      setSettings(newSettings);
      localStorage.setItem('bloom_settings', JSON.stringify(newSettings));

      const newProfileMeta: ProfileMeta = {
          id: newId,
          name: newSettings.name,
          status: 'planning',
          babyName: undefined,
          lastActive: new Date().toISOString()
      };

      const updatedProfiles = [...profiles, newProfileMeta];
      setProfiles(updatedProfiles);
      localStorage.setItem('bloom_all_profiles', JSON.stringify(updatedProfiles));

      // Force reload to apply clean state
      window.location.reload();
  };

  const calculations: PregnancyCalculations | null = useMemo(() => {
    if (!settings || !settings.lmp) return null;

    const lmpDate = new Date(settings.lmp);
    const now = new Date();
    const diffTime = Math.abs(now.getTime() - lmpDate.getTime());
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    // Logic: Naegele's rule adjusted
    const cycleAdjustment = settings.cycleLength - 28;
    const edd = new Date(lmpDate);
    edd.setDate(edd.getDate() + 280 + cycleAdjustment);

    const weeks = Math.floor(diffDays / 7);
    const days = diffDays % 7;

    let trimester: 1 | 2 | 3 = 1;
    if (weeks > 13) trimester = 2;
    if (weeks > 27) trimester = 3;

    return {
      edd,
      currentWeek: weeks === 0 ? 1 : weeks, // Minimum week 1
      currentDay: days,
      totalDays: diffDays,
      trimester,
      month: Math.ceil(weeks / 4.3),
      progressPercent: Math.min((diffDays / 280) * 100, 100)
    };
  }, [settings]);

  // Determine App Mode based on Settings Status
  const isPostpartum = settings?.status === 'postpartum';
  const isPlanning = settings?.status === 'planning';
  const isPregnant = settings?.status === 'pregnant';

  // Dynamic Theme Logic (Strict Gender Colors for Postpartum)
  let themeColor = 'text-pink-600';
  let activeBg = 'bg-pink-600 text-white shadow-pink-500/30';
  let bgGradient = 'bg-gradient-to-r from-pink-600 to-purple-600';
  let badgeColor = 'bg-pink-100 text-pink-600';

  if (isPlanning) {
      themeColor = 'text-teal-600';
      activeBg = 'bg-teal-600 text-white shadow-teal-500/30';
      bgGradient = 'bg-gradient-to-r from-teal-500 to-emerald-600';
      badgeColor = 'bg-teal-100 text-teal-600';
  } else if (isPostpartum) {
      if (settings?.babyGender === 'boy') {
          themeColor = 'text-blue-600';
          activeBg = 'bg-blue-600 text-white shadow-blue-500/30';
          bgGradient = 'bg-gradient-to-r from-blue-600 to-cyan-600';
          badgeColor = 'bg-blue-100 text-blue-600';
      } else {
          // Explicit Pink for Girl (Postpartum) to differ from Pregnancy Purple/Pink mix
          themeColor = 'text-rose-500';
          activeBg = 'bg-rose-500 text-white shadow-rose-500/30';
          bgGradient = 'bg-gradient-to-r from-rose-400 to-pink-500';
          badgeColor = 'bg-rose-100 text-rose-600';
      }
  }

  const getBabyAgeInWeeks = () => {
    if (!settings?.birthDate) return 0;
    const birth = new Date(settings.birthDate);
    const now = new Date();
    const diff = Math.abs(now.getTime() - birth.getTime());
    return Math.floor(diff / (1000 * 60 * 60 * 24 * 7));
  };

  const handleLogin = () => {
    setIsAuthenticated(true);
    localStorage.setItem('bloom_auth', 'true');
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem('bloom_auth');
    setActiveTab(TabView.DASHBOARD);
  };

  const handleOnboardingComplete = (data: UserSettings) => {
    // Inject ID if missing from Onboarding
    if (!data.id) data.id = 'profile_' + Date.now();

    // Initial sync of log if date provided
    if (data.lmp) {
        data.periodLog = [data.lmp];
        data.pregnancyLmp = data.status === 'pregnant' ? data.lmp : null;
    }

    // Ensure new fields are initialized
    if (!data.obstetricHistory) {
        data.obstetricHistory = {
            gravida: 1,
            para: 0,
            abortions: 0,
            abortionsT1: 0,
            abortionsT2: 0,
            living: 0,
            lastBabyCongenitalDefect: false
        };
    }
    if (data.age === undefined) data.age = 0;

    setSettings(data);
    localStorage.setItem('bloom_settings', JSON.stringify(data));

    // Initialize Profiles List for new user
    const meta: ProfileMeta = {
        id: data.id,
        name: data.name,
        status: data.status,
        babyName: data.babyName,
        babyGender: data.babyGender,
        birthDate: data.birthDate,
        lastActive: new Date().toISOString()
    };
    setProfiles([meta]);
    localStorage.setItem('bloom_all_profiles', JSON.stringify([meta]));
  };

  const handleUpdateProfile = (data: UserSettings) => {
    setSettings(data);
    localStorage.setItem('bloom_settings', JSON.stringify(data));

    // Update Meta in Profile List
    const updatedProfiles = profiles.map(p => 
        p.id === data.id ? { 
            ...p, 
            name: data.name, 
            status: data.status, 
            babyName: data.babyName,
            babyGender: data.babyGender,
            birthDate: data.birthDate
        } : p
    );
    setProfiles(updatedProfiles);
    localStorage.setItem('bloom_all_profiles', JSON.stringify(updatedProfiles));
  };

  const handleVaccineUpdate = (vaxId: string) => {
    if (!settings) return;
    const currentDone = settings.vaccinationsDone || [];
    let newDone;
    if (currentDone.includes(vaxId)) {
        newDone = currentDone.filter(id => id !== vaxId);
    } else {
        newDone = [...currentDone, vaxId];
    }
    const newSettings = { ...settings, vaccinationsDone: newDone };
    setSettings(newSettings);
    localStorage.setItem('bloom_settings', JSON.stringify(newSettings));
  };

  const handleReset = () => {
    localStorage.clear();
    setTimeout(() => {
        window.location.reload();
    }, 50);
  };

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  if (!settings) {
    return (
      <>
        <div className="fixed top-4 right-4 z-50">
           <button onClick={() => setDarkMode(!darkMode)} className="p-3 rounded-full bg-white dark:bg-deep-card shadow-lg text-bloom-DEFAULT dark:text-yellow-400">
             {darkMode ? <Sun size={20} /> : <Moon size={20} />}
           </button>
        </div>
        <Onboarding onComplete={handleOnboardingComplete} />
      </>
    );
  }

  // Determine Nav Items
  let navItems = [];

  if (isPlanning) {
      navItems = [
          { id: TabView.DASHBOARD, icon: Calendar, label: 'Cycle & Plan' },
          { id: TabView.HEALTH, icon: HeartPulse, label: 'Body Ready' },
          { id: TabView.MEDICINES, icon: Pill, label: 'Meds' },
          { id: TabView.TOOLS, icon: Wrench, label: 'Tools' }
      ];
  } else if (isPostpartum) {
      navItems = [
          { id: TabView.DASHBOARD, icon: Baby, label: 'Baby Care' },
          { id: TabView.HEALTH, icon: HeartPulse, label: 'Growth & Vitals' },
          { id: TabView.MEDICINES, icon: Pill, label: 'Meds' },
          { id: TabView.VACCINATIONS, icon: Syringe, label: 'Vaccines' }, 
          { id: TabView.DIET, icon: Utensils, label: 'Mom Diet' }
      ];
  } else {
      // Pregnant
      navItems = [
          { id: TabView.DASHBOARD, icon: LayoutDashboard, label: 'Dashboard' },
          { id: TabView.HEALTH, icon: HeartPulse, label: 'Vitals' },
          { id: TabView.TOOLS, icon: Wrench, label: 'Tools' },
          { id: TabView.TIMELINE, icon: Calendar, label: 'Timeline' },
          { id: TabView.MEDICINES, icon: Pill, label: 'Meds' },
          { id: TabView.DIET, icon: Utensils, label: 'Diet Plan' },
          { id: TabView.VACCINATIONS, icon: Syringe, label: 'Vaccines' },
          { id: TabView.REPORTS, icon: FileText, label: 'Reports' },
      ];
  }

  const renderContent = () => {
    const calcSafe = calculations || { 
        currentWeek: 0, edd: new Date(), currentDay: 0, totalDays: 0, trimester: 1, month: 1, progressPercent: 0 
    } as PregnancyCalculations;

    // Use a key based on profile ID to force re-mount components when switching profiles
    const profileKey = settings.id;

    switch(activeTab) {
      case TabView.DASHBOARD: 
        if (isPlanning) return <PrePregnancyDashboard key={`plan_${profileKey}`} settings={settings} onUpdateSettings={handleUpdateProfile} />;
        if (isPostpartum) return <PostpartumDashboard key={`pp_${profileKey}`} settings={settings} />;
        return <Dashboard key={`preg_${profileKey}`} calculations={calcSafe} settings={settings} />;

      case TabView.TIMELINE: return <Timeline key={`time_${profileKey}`} calculations={calcSafe} settings={settings} />;
      case TabView.REPORTS: return <ReportAnalyzer key={`rep_${profileKey}`} />;
      case TabView.MEDICINES: return <MedicineTracker key={`med_${profileKey}`} currentWeek={calcSafe.currentWeek} isPostpartum={isPostpartum} />;
      case TabView.DIET: return <DietPlan key={`diet_${profileKey}`} settings={settings} calculations={calcSafe} />;
      case TabView.VACCINATIONS: 
        return <VaccinationTracker 
            key={`vax_${profileKey}`}
            settings={settings} 
            currentWeek={isPostpartum ? getBabyAgeInWeeks() : calcSafe.currentWeek} 
            onUpdate={handleVaccineUpdate} 
        />;
      case TabView.HEALTH: return <HealthTracker key={`health_${profileKey}`} settings={settings} calculations={calcSafe} />;
      case TabView.TOOLS: return <ToolsHub key={`tools_${profileKey}`} />;
      case TabView.PROFILE: 
        return <Profile 
            key={`prof_${profileKey}`}
            settings={settings} 
            profiles={profiles} // Pass list for management
            onUpdate={handleUpdateProfile} 
            onReset={handleReset} 
            onAddProfile={handleAddProfile}
            onSwitchProfile={handleSwitchProfile}
        />;
      default: return null;
    }
  };

  return (
    <div className="flex h-screen w-full overflow-hidden bg-bloom-light dark:bg-deep-bg transition-colors duration-300">

      {/* Sidebar - Desktop */}
      <aside className="hidden md:flex w-64 flex-col bg-white dark:bg-deep-card border-r border-gray-200 dark:border-indigo-950 shrink-0 h-full">
         <div className="p-6">
             <h1 className={`text-2xl font-bold bg-clip-text text-transparent ${bgGradient}`}>
                {isPlanning ? "Bloom Plan" : isPostpartum ? (settings.babyGender === 'boy' ? "Bloom Baby" : "Bloom Baby") : "Bloom Bump"}
             </h1>
             {/* Mini Profile Switcher */}
             {profiles.length > 1 && (
                 <div className="mt-2 flex items-center gap-2 cursor-pointer" onClick={() => setActiveTab(TabView.PROFILE)}>
                     <div className="flex -space-x-2">
                         {profiles.slice(0, 3).map(p => (
                             <div key={p.id} className="w-6 h-6 rounded-full border border-white bg-gray-200 flex items-center justify-center text-[10px] overflow-hidden">
                                 {p.babyName ? p.babyName[0] : p.name[0]}
                             </div>
                         ))}
                     </div>
                     <span className="text-xs text-gray-500 underline">Switch Profile</span>
                 </div>
             )}
         </div>

         <nav className="flex-1 p-4 space-y-2 overflow-y-auto custom-scrollbar">
            {navItems.map(item => (
               <button
                 key={item.id}
                 onClick={() => setActiveTab(item.id)}
                 className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all font-medium ${activeTab === item.id ? `${activeBg} shadow-lg` : 'text-gray-700 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-white/5'}`}
               >
                  <item.icon size={20} />
                  {item.label}
               </button>
            ))}
         </nav>

         <div className="p-4 border-t border-gray-200 dark:border-indigo-950 mt-auto">
            <div 
              onClick={() => setActiveTab(TabView.PROFILE)}
              className="flex items-center gap-3 px-4 py-3 rounded-xl bg-gray-100 dark:bg-indigo-950/50 mb-2 cursor-pointer hover:bg-gray-200 dark:hover:bg-indigo-900 transition-colors"
            >
                <div className={`w-8 h-8 rounded-full ${badgeColor} flex items-center justify-center font-bold`}>
                    {settings.name.charAt(0).toUpperCase()}
                </div>
                <div className="flex-1 overflow-hidden">
                    <p className="text-sm font-bold truncate text-gray-800 dark:text-white">{settings.babyName || settings.name}</p>
                    <p className="text-xs text-gray-500 truncate capitalize">
                        {settings.status === 'postpartum' && settings.babyName ? 'Baby Profile' : settings.status}
                    </p>
                </div>
                <Settings size={16} className="text-gray-400" />
            </div>
            <button 
              onClick={handleLogout}
              className="w-full flex items-center gap-2 px-4 py-2 text-sm text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors"
            >
              <LogOut size={16} /> Sign Out
            </button>
         </div>
      </aside>

      {/* Mobile Nav - Fixed Bottom */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white dark:bg-deep-card border-t border-gray-200 dark:border-indigo-950 z-50 flex flex-col safe-area-bottom shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]">
         <div className="flex items-center gap-1 overflow-x-auto px-2 py-2 w-full no-scrollbar">
            {[
              ...navItems,
              { id: TabView.PROFILE, icon: User, label: 'Profile' },
            ].map(item => (
               <button
                 key={item.id}
                 onClick={() => setActiveTab(item.id)}
                 className={`flex-shrink-0 flex flex-col items-center gap-1 p-2 rounded-xl transition-all min-w-[64px] ${activeTab === item.id ? themeColor : 'text-gray-400'}`}
               >
                  <item.icon size={22} />
                  <span className="text-[10px] font-medium whitespace-nowrap">{item.label}</span>
               </button>
            ))}
         </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative">
         <header className="h-16 flex items-center justify-between px-4 md:px-8 border-b border-gray-200 dark:border-indigo-950 bg-white/50 dark:bg-deep-card/50 backdrop-blur-md sticky top-0 z-40 shrink-0">
            <div className="flex items-center gap-2">
                <h2 className="text-lg md:text-xl font-bold text-gray-800 dark:text-white capitalize truncate">
                    {activeTab === TabView.VACCINATIONS ? 'Vaccinations' : activeTab.replace('-', ' ')}
                </h2>
                {profiles.length > 1 && (
                    <span className="text-xs px-2 py-0.5 rounded-full bg-gray-100 dark:bg-indigo-900 text-gray-500 dark:text-gray-400 border border-gray-200 dark:border-indigo-700 hidden md:inline-block">
                        Active: {settings.babyName || "Profile 1"}
                    </span>
                )}
            </div>
            <button 
              onClick={() => setDarkMode(!darkMode)}
              className="p-2 rounded-full bg-white dark:bg-indigo-900/50 border border-gray-200 dark:border-indigo-800 text-gray-600 dark:text-yellow-400 transition-colors shadow-sm"
            >
              {darkMode ? <Sun size={20} /> : <Moon size={20} />}
            </button>
         </header>

         <div className="flex-1 overflow-y-auto overflow-x-hidden p-4 md:p-8 pb-28 md:pb-8 custom-scrollbar scroll-smooth w-full">
            <div className="max-w-7xl mx-auto w-full">
              {renderContent()}
            </div>
         </div>
      </main>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { UserSettings, DietType, AppMode, ProfileMeta } from '../types';
import { Button } from './Button';
import { RefreshCw, User, Calendar, Activity, Utensils, Baby, Ruler, Weight, ArrowRightLeft, HeartPulse, Droplet, AlertTriangle, CheckCircle2, FlaskConical, Stethoscope, Info, X, Users, Plus, ChevronRight, FileText, Clock } from 'lucide-react';
import { COMORBIDITY_GUIDELINES, BLOOD_GROUPS } from '../constants';

interface Props {
  settings: UserSettings;
  profiles?: ProfileMeta[]; // New prop for listing profiles
  onUpdate: (settings: UserSettings) => void;
  onReset: () => void;
  onAddProfile?: () => void;
  onSwitchProfile?: (id: string) => void;
}

export const Profile: React.FC<Props> = ({ settings, profiles = [], onUpdate, onReset, onAddProfile, onSwitchProfile }) => {
  const [formData, setFormData] = useState<UserSettings>(settings);
  const [saved, setSaved] = useState(false);

  // Modals
  const [showBabyModal, setShowBabyModal] = useState(false);
  const [showResetConfirm, setShowResetConfirm] = useState(false);

  const [babyForm, setBabyForm] = useState<{name: string, date: string, gender: 'boy' | 'girl'}>({ name: '', date: '', gender: 'boy' });

  useEffect(() => {
    // Ensure new fields are initialized
    setFormData({
      ...settings,
      comorbidities: settings.comorbidities || [],
      dietaryPreference: settings.dietaryPreference || 'vegetarian',
      lactoseIntolerant: settings.lactoseIntolerant || false,
      vaccinationsDone: settings.vaccinationsDone || [],
      maternalBloodGroup: settings.maternalBloodGroup || '',
      paternalBloodGroup: settings.paternalBloodGroup || '',
      age: settings.age || undefined,
      paternalHeightCm: settings.paternalHeightCm || undefined,
      status: settings.status || (settings.isPostpartum ? 'postpartum' : 'pregnant'),
      periodLog: settings.periodLog || [],
      pregnancyLmp: settings.pregnancyLmp || null,
      obstetricHistory: settings.obstetricHistory || {
          gravida: 1,
          para: 0,
          abortions: 0,
          abortionsT1: 0,
          abortionsT2: 0,
          living: 0,
          lastBabyCongenitalDefect: false,
          lastBabyDefectDetails: ''
      }
    });
  }, [settings]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Logic to save specific LMPs based on current mode
    let updatedSettings = { ...formData };

    if (formData.status === 'pregnant') {
        updatedSettings.pregnancyLmp = formData.lmp;
    } else if (formData.status === 'planning') {
        // If LMP changed, ensure it's in the log
        if (formData.lmp && !updatedSettings.periodLog.includes(formData.lmp)) {
            updatedSettings.periodLog = [...updatedSettings.periodLog, formData.lmp].sort().reverse();
        }
    }

    onUpdate(updatedSettings);
    setSaved(true);
    setTimeout(() => setSaved(false), 2000);
  };

  const toggleComorbidity = (id: string) => {
    const current = formData.comorbidities || [];
    if (current.includes(id)) {
      setFormData({ ...formData, comorbidities: current.filter(c => c !== id) });
    } else {
      setFormData({ ...formData, comorbidities: [...current, id] });
    }
  };

  // Switch to Postpartum (Baby Born)
  const enablePostpartumMode = () => {
    if(babyForm.name && babyForm.date) {
        onUpdate({
            ...formData,
            status: 'postpartum',
            isPostpartum: true, // legacy sync
            babyName: babyForm.name,
            babyGender: babyForm.gender,
            birthDate: babyForm.date
        });
        setShowBabyModal(false);
    }
  };

  const handleModeChange = (newMode: AppMode) => {
      if (newMode === 'postpartum') {
          setShowBabyModal(true);
          return;
      }

      let newLmp = formData.lmp;

      if (newMode === 'pregnant') {
          // If switching TO pregnant, prefer the saved pregnancy LMP, 
          // otherwise assume the last logged period was the conception period.
          if (formData.pregnancyLmp) {
              newLmp = formData.pregnancyLmp;
          } else if (formData.periodLog && formData.periodLog.length > 0) {
              // Sort descending to get latest
              const sorted = [...formData.periodLog].sort((a, b) => new Date(b).getTime() - new Date(a).getTime());
              newLmp = sorted[0];
          }
      } else if (newMode === 'planning') {
          // If switching TO planning, show the latest period log
          if (formData.periodLog && formData.periodLog.length > 0) {
              const sorted = [...formData.periodLog].sort((a, b) => new Date(b).getTime() - new Date(a).getTime());
              newLmp = sorted[0];
          }
      }

      onUpdate({
          ...formData,
          status: newMode,
          isPostpartum: false,
          lmp: newLmp
      });
  };

  // --- Blood Group Logic ---
  const calculateBloodGroupData = () => {
      const mom = formData.maternalBloodGroup;
      const dad = formData.paternalBloodGroup;
      if (!mom || !dad) return null;

      const momType = mom.slice(0, -1);
      const momRh = mom.slice(-1);
      const dadType = dad.slice(0, -1);
      const dadRh = dad.slice(-1);

      // 1. Prediction Logic (Simplified)
      let possibleABO: string[] = [];
      const getAlleles = (type: string) => {
          if (type === 'A') return ['A', 'O']; 
          if (type === 'B') return ['B', 'O'];
          if (type === 'AB') return ['A', 'B'];
          return ['O', 'O'];
      };

      const momAlleles = getAlleles(momType);
      const dadAlleles = getAlleles(dadType);

      const combinations = new Set<string>();
      momAlleles.forEach(m => {
          dadAlleles.forEach(d => {
              let geno = [m, d].sort().join('');
              if (geno === 'AA' || geno === 'AO') combinations.add('A');
              else if (geno === 'BB' || geno === 'BO') combinations.add('B');
              else if (geno === 'AB') combinations.add('AB');
              else if (geno === 'OO') combinations.add('O');
          });
      });
      possibleABO = Array.from(combinations).sort();

      let possibleRh = [];
      if (momRh === '-' && dadRh === '-') {
          possibleRh = ['-'];
      } else {
          possibleRh = ['+', '-'];
      }

      const possibleGroups: string[] = [];
      possibleABO.forEach(abo => {
          possibleRh.forEach(rh => {
              possibleGroups.push(abo + rh);
          });
      });

      // 2. Compatibility Logic
      const isMomRhNeg = momRh === '-';
      const isDadRhPos = dadRh === '+';
      const isAboRisk = momType === 'O' && (dadType === 'A' || dadType === 'B' || dadType === 'AB');

      let risk = { type: 'safe', severity: 'low', title: 'Compatible', message: 'No major incompatibility risks detected.' };

      if (isMomRhNeg && isDadRhPos) {
          risk = {
              type: 'rh_risk',
              severity: 'high',
              title: 'Rh Incompatibility Risk',
              message: "Mom is Rh(-) and Dad is Rh(+). If baby is Rh(+), Anti-D injection (RhoGAM) may be needed."
          };
      } else if (isAboRisk) {
          risk = {
              type: 'abo_risk',
              severity: 'medium',
              title: 'ABO Incompatibility Risk',
              message: "Mom is Type O and Dad is non-O. Baby may have mild jaundice after birth."
          };
      }

      return { possibilities: possibleGroups, risk };
  };

  const bloodData = calculateBloodGroupData();

  // --- Baby Height Prediction ---
  const predictHeight = () => {
      if (formData.heightCm && formData.paternalHeightCm) {
          const m = formData.heightCm;
          const f = formData.paternalHeightCm;
          const boyTarget = (m + f + 13) / 2;
          const girlTarget = (m + f - 13) / 2;
          return { boy: boyTarget.toFixed(1), girl: girlTarget.toFixed(1) };
      }
      return null;
  };
  const predictedHeight = predictHeight();

  const getThemeColor = () => {
      if (settings.status === 'planning') return 'from-teal-500 to-emerald-600';
      if (settings.status === 'postpartum') {
          return settings.babyGender === 'boy' ? 'from-blue-600 to-cyan-600' : 'from-rose-400 to-pink-500';
      }
      return 'from-pink-600 to-purple-600'; 
  };

  const calculateAge = (birthDateString: string) => {
      const birth = new Date(birthDateString);
      const now = new Date();
      const diffTime = Math.abs(now.getTime() - birth.getTime());
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (diffDays < 30) return `${diffDays} days old`;
      const months = Math.floor(diffDays / 30.4);
      if (months < 12) return `${months} months old`;
      const years = Math.floor(months / 12);
      const remMonths = months % 12;
      return `${years}y ${remMonths}m old`;
  };

  const updateObstetric = (field: string, value: any) => {
      setFormData({
          ...formData,
          obstetricHistory: {
              ...formData.obstetricHistory,
              [field]: value
          }
      });
  };

  return (
    <div className="max-w-2xl mx-auto space-y-8 animate-fade-in pb-10">

      {/* Mode Switcher Block */}
      <div className={`rounded-3xl p-6 text-white shadow-lg bg-gradient-to-r ${getThemeColor()}`}>
          <div className="flex flex-col md:flex-row gap-6 items-start md:items-center justify-between">
              <div>
                  <h3 className="text-lg font-bold flex items-center gap-2 opacity-90 text-sm uppercase tracking-wider mb-2">
                       Current Stage
                  </h3>
                  <p className="text-2xl font-bold leading-tight">
                    {settings.status === 'planning' ? 'Planning Pregnancy' : settings.status === 'postpartum' ? 'Postpartum' : 'Pregnant'}
                  </p>
              </div>
              <div className="flex flex-wrap gap-2 w-full md:w-auto">
                  <button 
                    onClick={() => handleModeChange('planning')}
                    className={`flex-1 md:flex-none px-4 py-2 rounded-full text-sm font-bold transition-all border whitespace-nowrap ${settings.status === 'planning' ? 'bg-white text-teal-700 border-white shadow-md' : 'bg-black/10 text-white border-white/20 hover:bg-white/10'}`}
                  >
                      Planning
                  </button>
                  <button 
                    onClick={() => handleModeChange('pregnant')}
                    className={`flex-1 md:flex-none px-4 py-2 rounded-full text-sm font-bold transition-all border whitespace-nowrap ${settings.status === 'pregnant' ? 'bg-white text-pink-700 border-white shadow-md' : 'bg-black/10 text-white border-white/20 hover:bg-white/10'}`}
                  >
                      Pregnant
                  </button>
                  <button 
                    onClick={() => handleModeChange('postpartum')}
                    className={`flex-1 md:flex-none px-4 py-2 rounded-full text-sm font-bold transition-all border whitespace-nowrap ${settings.status === 'postpartum' ? 'bg-white text-blue-700 border-white shadow-md' : 'bg-black/10 text-white border-white/20 hover:bg-white/10'}`}
                  >
                      Baby Born
                  </button>
              </div>
          </div>
      </div>

      {/* FAMILY HUB / MULTIPARITY SUPPORT */}
      <div className="bg-white dark:bg-deep-card p-6 rounded-3xl shadow-lg border border-gray-100 dark:border-indigo-800">
          <div className="flex items-center justify-between mb-4 border-b border-gray-100 dark:border-indigo-800 pb-4">
              <h3 className="text-xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
                  <Users size={20} className="text-indigo-600 dark:text-indigo-400" /> My Family Hub
              </h3>
              {onAddProfile && (
                  <Button onClick={onAddProfile} variant="secondary" className="text-xs">
                      <Plus size={16} /> Add Baby
                  </Button>
              )}
          </div>

          <div className="grid gap-3">
              {profiles.map(p => {
                  const isActive = p.id === settings.id;
                  let statusColor = 'bg-gray-500';
                  let icon = <Baby size={20} />;

                  if (p.status === 'planning') {
                      statusColor = 'bg-teal-500';
                      icon = <Calendar size={18} />;
                  } else if (p.status === 'postpartum') {
                      if (p.babyGender === 'boy') {
                          statusColor = 'bg-blue-500';
                      } else {
                          statusColor = 'bg-pink-500';
                      }
                  } else {
                      statusColor = 'bg-purple-500';
                  }

                  return (
                      <div 
                        key={p.id}
                        className={`flex items-center justify-between p-4 rounded-2xl border transition-all ${
                            isActive 
                                ? 'bg-indigo-50 dark:bg-indigo-900/30 border-indigo-200 dark:border-indigo-700 shadow-sm' 
                                : 'bg-gray-50 dark:bg-gray-800/50 border-gray-100 dark:border-indigo-900/30 hover:bg-gray-100 dark:hover:bg-indigo-900/20'
                        }`}
                      >
                          <div className="flex items-center gap-4">
                              <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-white shadow-sm ${statusColor}`}>
                                  {p.babyName ? p.babyName[0].toUpperCase() : icon}
                              </div>
                              <div>
                                  <p className="font-bold text-gray-900 dark:text-white flex items-center gap-2">
                                      {p.babyName || (p.status === 'planning' ? 'Future Baby' : 'Baby Profile')}
                                      {p.status === 'postpartum' && (
                                          <span className={`text-[10px] px-1.5 py-0.5 rounded-full font-bold uppercase ${p.babyGender === 'boy' ? 'bg-blue-100 text-blue-700' : 'bg-pink-100 text-pink-700'}`}>
                                              {p.babyGender}
                                          </span>
                                      )}
                                  </p>
                                  <div className="flex gap-2 text-xs text-gray-500 dark:text-gray-400 items-center">
                                      <span className="capitalize">{p.status}</span>
                                      {p.birthDate && (
                                          <>
                                            <span className="w-1 h-1 bg-gray-300 rounded-full"></span>
                                            <span className="flex items-center gap-1"><Clock size={10} /> {calculateAge(p.birthDate)}</span>
                                          </>
                                      )}
                                      {isActive && <span className="ml-1 px-1.5 py-0.5 bg-green-100 text-green-700 rounded text-[10px] font-bold">ACTIVE</span>}
                                  </div>
                              </div>
                          </div>

                          {!isActive && onSwitchProfile && (
                              <button 
                                onClick={() => onSwitchProfile(p.id)}
                                className="text-sm font-medium text-indigo-600 dark:text-indigo-400 flex items-center gap-1 hover:underline"
                              >
                                  Switch <ChevronRight size={16} />
                              </button>
                          )}
                      </div>
                  );
              })}
          </div>
      </div>

      <div className="bg-white dark:bg-deep-card p-8 rounded-3xl shadow-lg border border-gray-100 dark:border-indigo-800">
        <form onSubmit={handleSubmit} className="space-y-8">
          {/* Form Content ... (Existing fields) */}

          <div className="space-y-6">
            <h3 className="font-bold text-gray-800 dark:text-white flex items-center gap-2 border-b border-gray-100 dark:border-indigo-800 pb-3 mb-4">
                <User size={20} className="text-pink-500" /> Personal Details
            </h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Your Name</label>
                    <input
                        type="text"
                        required
                        className="w-full px-4 py-3 rounded-xl border border-gray-200 dark:border-indigo-700 bg-white dark:bg-indigo-950/50 text-gray-900 dark:text-white outline-none focus:ring-2 focus:ring-pink-500 transition-all"
                        value={formData.name}
                        onChange={(e) => setFormData({...formData, name: e.target.value})}
                    />
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Maternal Age (Required)</label>
                    <input
                        type="number"
                        required
                        className="w-full px-4 py-3 rounded-xl border border-gray-200 dark:border-indigo-700 bg-white dark:bg-indigo-950/50 text-gray-900 dark:text-white outline-none focus:ring-2 focus:ring-pink-500 transition-all"
                        value={formData.age || ''}
                        onChange={(e) => setFormData({...formData, age: parseInt(e.target.value)})}
                        placeholder="e.g. 28"
                    />
                    <p className="text-[10px] text-gray-400 mt-1">Age is vital for calculating pregnancy risks (FOGSI Guidelines).</p>
                </div>
            </div>

            {/* OBSTETRIC HISTORY */}
            <h3 className="font-bold text-gray-800 dark:text-white flex items-center gap-2 border-b border-gray-100 dark:border-indigo-800 pb-3 pt-4 mb-4">
                <FileText size={20} className="text-teal-500" /> Obstetric History
            </h3>
            <div className="p-5 bg-teal-50 dark:bg-teal-900/10 rounded-2xl space-y-5 border border-teal-100 dark:border-teal-900/30">
                <div className="grid grid-cols-2 gap-6">
                    <div>
                        <label className="block text-xs font-bold uppercase text-gray-600 dark:text-gray-300 mb-1">Total Pregnancies (Gravida)</label>
                        <input
                            type="number"
                            min="1"
                            className="w-full px-4 py-2 rounded-xl border border-gray-200 dark:border-indigo-700 bg-white dark:bg-deep-bg text-gray-900 dark:text-white"
                            value={formData.obstetricHistory.gravida}
                            onChange={(e) => updateObstetric('gravida', parseInt(e.target.value))}
                        />
                    </div>
                    <div>
                        <label className="block text-xs font-bold uppercase text-gray-600 dark:text-gray-300 mb-1">Live Births (Para)</label>
                        <input
                            type="number"
                            min="0"
                            className="w-full px-4 py-2 rounded-xl border border-gray-200 dark:border-indigo-700 bg-white dark:bg-deep-bg text-gray-900 dark:text-white"
                            value={formData.obstetricHistory.para}
                            onChange={(e) => updateObstetric('para', parseInt(e.target.value))}
                        />
                    </div>
                </div>

                {formData.obstetricHistory.gravida > formData.obstetricHistory.para + (formData.status === 'pregnant' ? 1 : 0) && (
                    <div className="space-y-3">
                        <p className="text-sm font-bold text-red-600 dark:text-red-400">Abortion / Miscarriage History (Required for Risk Calc)</p>
