          const f = formData.paternalHeightCm;
          const boyTarget = (m + f + 13) / 2;
          const girlTarget = (m + f - 13) / 2;
          return { boy: boyTarget.toFixed(1), girl: girlTarget.toFixed(1) };
      }
      return null;
  };
  const predictedHeight = predictHeight();

