import React, { useState } from 'react';
import { Upload, FileText, X, AlertTriangle, CheckCircle, Key } from 'lucide-react';
import { Button } from './Button';
import { analyzeMedicalReport } from '../services/geminiService';
import { ReportAnalysis } from '../types';

export const ReportAnalyzer: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [report, setReport] = useState<ReportAnalysis | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [missingKey, setMissingKey] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selected = e.target.files[0];
      setFile(selected);

      const reader = new FileReader();
      reader.onloadend = () => {
        setPreview(reader.result as string);
      };
      reader.readAsDataURL(selected);
      setReport(null);
      setError(null);
      setMissingKey(false);
    }
  };

  const handleAnalyze = async () => {
    if (!file || !preview) return;

    setAnalyzing(true);
    setError(null);
    setMissingKey(false);

    try {
      const base64Data = preview.split(',')[1];
      const mimeType = file.type;

      const result = await analyzeMedicalReport(base64Data, mimeType, "Patient is currently in 2nd Trimester.");
      setReport(result);
    } catch (err: any) {
      if (err.message === 'MISSING_API_KEY') {
          setMissingKey(true);
      } else {
          setError("Failed to analyze the document. Ensure it is a clear image.");
      }
    } finally {
      setAnalyzing(false);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-full">
      {/* Upload Section */}
      <div className="flex flex-col gap-6">
        <div className="bg-white dark:bg-deep-card p-8 rounded-3xl shadow-lg border-2 border-dashed border-gray-300 dark:border-indigo-700 hover:border-bloom-DEFAULT dark:hover:border-bloom-DEFAULT transition-colors text-center relative">

          {!preview ? (
            <>
              <div className="w-16 h-16 bg-gray-100 dark:bg-indigo-900/50 rounded-full flex items-center justify-center mx-auto mb-4 text-gray-500 dark:text-indigo-300">
                <Upload size={32} />
              </div>
              <h3 className="text-xl font-bold text-gray-800 dark:text-white mb-2">Upload Report</h3>
              <p className="text-gray-500 dark:text-gray-400 mb-6">Support for USG images, Blood test photos (JPG/PNG)</p>

              <input 
                type="file" 
                accept="image/*"
                onChange={handleFileChange}
                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
              />
              <Button className="mx-auto pointer-events-none">Select File</Button>
            </>
          ) : (
            <div className="relative h-full flex flex-col items-center">
              <img src={preview} alt="Preview" className="max-h-64 rounded-xl shadow-md mb-4" />
              <div className="flex gap-4">
                  <Button onClick={handleAnalyze} isLoading={analyzing}>Analyze with AI</Button>
                  <Button variant="ghost" onClick={() => { setFile(null); setPreview(null); setReport(null); }}>
                    <X size={20} /> Remove
                  </Button>
              </div>
            </div>
          )}
        </div>

        {missingKey && (
            <div className="p-4 bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-300 rounded-xl flex items-center gap-3 border border-red-200 dark:border-red-800">
                <Key size={24} className="shrink-0" />
                <div>
                    <strong>AI Key Missing:</strong> You need a Gemini API Key to use this feature. Please add it in your Profile.
                </div>
            </div>
        )}

        {error && (
            <div className="p-4 bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-300 rounded-xl flex items-center gap-2">
                <AlertTriangle size={20} /> {error}
            </div>
        )}
      </div>

      {/* Result Section */}
      <div className="bg-white dark:bg-deep-card rounded-3xl shadow-lg border border-bloom-100 dark:border-indigo-800 p-6 flex flex-col overflow-hidden">
        <div className="flex items-center justify-between mb-6 border-b border-gray-100 dark:border-indigo-800 pb-4">
            <h3 className="text-xl font-bold flex items-center gap-2 text-gray-800 dark:text-white">
                <FileText className="text-bloom-DEFAULT" /> Analysis Results
            </h3>
            {report && <span className="px-3 py-1 bg-green-100 text-green-700 rounded-full text-xs font-bold uppercase">{report.type}</span>}
        </div>

        {analyzing ? (
            <div className="flex-1 flex flex-col items-center justify-center text-gray-400 gap-4">
                <div className="animate-pulse flex space-x-4">
                    <div className="flex-1 space-y-4 py-1">
                        <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-3/4"></div>
                        <div className="space-y-2">
                            <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded"></div>
                            <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-5/6"></div>
                        </div>
                    </div>
                </div>
                <p>Analyzing document...</p>
            </div>
        ) : report ? (
            <div className="space-y-6 overflow-y-auto pr-2 custom-scrollbar h-[500px]">
                <div>
                    <h4 className="font-bold text-gray-700 dark:text-gray-300 mb-2">Summary</h4>
                    <p className="text-gray-600 dark:text-gray-400 bg-gray-50 dark:bg-indigo-950/30 p-4 rounded-xl">
                        {report.summary}
                    </p>
                </div>

                {report.warnings.length > 0 && (
                    <div>
                        <h4 className="font-bold text-red-600 dark:text-red-400 mb-2 flex items-center gap-2">
                            <AlertTriangle size={16} /> Alerts
                        </h4>
                        <ul className="space-y-2">
                            {report.warnings.map((w, i) => (
                                <li key={i} className="flex items-start gap-2 text-sm text-red-700 dark:text-red-300 bg-red-50 dark:bg-red-900/20 p-3 rounded-lg border border-red-100 dark:border-red-900/30">
                                    <span>•</span> {w}
                                </li>
                            ))}
                        </ul>
                    </div>
                )}

                {report.recommendations.length > 0 && (
                    <div>
                        <h4 className="font-bold text-green-600 dark:text-green-400 mb-2 flex items-center gap-2">
                            <CheckCircle size={16} /> Recommendations
                        </h4>
                        <ul className="space-y-2">
                            {report.recommendations.map((r, i) => (
                                <li key={i} className="flex items-start gap-2 text-sm text-green-700 dark:text-green-300 bg-green-50 dark:bg-green-900/20 p-3 rounded-lg border border-green-100 dark:border-green-900/30">
                                    <span>•</span> {r}
                                </li>
                            ))}
                        </ul>
                    </div>
                )}

                <div className="pt-4 border-t border-gray-100 dark:border-gray-800">
                    <p className="text-xs text-gray-400">
                        Disclaimer: This analysis is generated by AI and should not replace professional medical advice. Always consult your doctor.
                    </p>
                </div>
            </div>
        ) : (
            <div className="flex-1 flex items-center justify-center text-gray-400 text-center p-8">
                <p>Upload a document to see the detailed breakdown here.</p>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Button } from './Button';
import { Search, ShieldCheck, AlertTriangle, XCircle, Info, ChevronDown, ChevronUp, Octagon, Key } from 'lucide-react';
import { checkMedicineSafety } from '../services/geminiService';
import { MedicineSafetyResult } from '../types';
import { MEDICINE_DATABASE, ALWAYS_CONTRAINDICATED } from '../constants';

interface Props {
  currentWeek: number;
  isPostpartum: boolean;
}

export const MedicineSafety: React.FC<Props> = ({ currentWeek, isPostpartum }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<MedicineSafetyResult | null>(null);
  const [expandedCategory, setExpandedCategory] = useState<number | null>(0);
  const [showContraindicated, setShowContraindicated] = useState(false);
  const [missingKey, setMissingKey] = useState(false);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchTerm.trim()) return;
    setLoading(true);
    setMissingKey(false);

    try {
        // Determine context for AI
        const context = isPostpartum ? 'lactation' : 'pregnancy';
        const res = await checkMedicineSafety(searchTerm, currentWeek, context);
        setResult(res);
    } catch (err: any) {
        if (err.message === 'MISSING_API_KEY') {
            setMissingKey(true);
            setResult(null);
        }
    } finally {
        setLoading(false);
    }
  };

  // Logic for picking database based on profile mode
  let guideData;
  let trimesterTitle;

  if (isPostpartum) {
      // Use key 4 for Postpartum/Lactation
      guideData = MEDICINE_DATABASE[4];
      trimesterTitle = "Lactation / Postpartum";
  } else {
      const trimester = currentWeek <= 13 ? 1 : currentWeek <= 27 ? 2 : 3;
      guideData = MEDICINE_DATABASE[trimester] || MEDICINE_DATABASE[1];
      trimesterTitle = `Trimester ${trimester}`;
  }

  const getStatusColor = (status: string) => {
    switch(status) {
      case 'Safe': return 'bg-green-100 text-green-700 border-green-200 dark:bg-green-900/30 dark:text-green-300 dark:border-green-800';
      case 'Caution': return 'bg-yellow-100 text-yellow-700 border-yellow-200 dark:bg-yellow-900/30 dark:text-yellow-300 dark:border-yellow-800';
      case 'Unsafe': return 'bg-red-100 text-red-700 border-red-200 dark:bg-red-900/30 dark:text-red-300 dark:border-red-800';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const getStatusIcon = (status: string) => {
    switch(status) {
      case 'Safe': return <ShieldCheck size={24} />;
      case 'Caution': return <AlertTriangle size={24} />;
      case 'Unsafe': return <XCircle size={24} />;
      default: return <Info size={24} />;
    }
  };

  const toggleCategory = (idx: number) => {
    setExpandedCategory(expandedCategory === idx ? null : idx);
  };

  return (
    <div className="space-y-8">
      {/* Search Section */}
      <div className="bg-white dark:bg-deep-card p-6 rounded-3xl shadow-lg border border-gray-100 dark:border-indigo-800">
        <h3 className="text-xl font-bold mb-4 text-gray-800 dark:text-white flex items-center gap-2">
            AI Safety Check
            {isPostpartum && <span className="text-xs bg-purple-100 text-purple-700 px-2 py-1 rounded-full">Lactation Focus</span>}
        </h3>
        <p className="text-sm text-gray-500 mb-4">
          Verify any specific medicine for {isPostpartum ? "breastfeeding safety" : `Week ${currentWeek} (Trimester ${trimesterTitle})`}.
        </p>
        <form onSubmit={handleSearch} className="flex gap-2">
          <input 
            type="text" 
            placeholder="Enter medicine name (e.g. Ibuprofen)" 
            className="flex-1 px-4 py-3 rounded-xl border border-gray-200 dark:border-indigo-700 bg-gray-50 dark:bg-indigo-950/50 text-gray-900 dark:text-white placeholder-gray-400 dark:placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-bloom-DEFAULT"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <Button type="submit" isLoading={loading}>
            <Search size={20} />
          </Button>
        </form>

        {missingKey && (
            <div className="mt-6 p-4 bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-300 rounded-xl flex items-center gap-3 border border-red-200 dark:border-red-800">
                <Key size={24} className="shrink-0" />
                <div>
                    <strong>AI Key Missing:</strong> To use AI safety checks, please add your Google Gemini API Key in your Profile.
                </div>
            </div>
        )}

        {result && (
          <div className={`mt-6 p-6 rounded-2xl border ${getStatusColor(result.status)} animate-fade-in`}>
             <div className="flex items-start gap-4">
                <div className="mt-1">{getStatusIcon(result.status)}</div>
                <div>
                   <h4 className="font-bold text-lg mb-1">{result.status}</h4>
                   <p className="mb-3 leading-relaxed">{result.description}</p>
                   {result.alternatives && result.alternatives.length > 0 && (
                     <div className="text-sm opacity-90">
                       <strong>Alternatives:</strong> {result.alternatives.join(', ')}
                     </div>
                   )}
                </div>
             </div>
          </div>
        )}
      </div>

       {/* Contraindicated List (Collapsible) */}
       <div className="bg-red-50 dark:bg-red-900/10 border-2 border-red-200 dark:border-red-900/50 rounded-2xl overflow-hidden">
          <button 
             onClick={() => setShowContraindicated(!showContraindicated)}
             className="w-full flex items-center justify-between p-4 bg-red-100 dark:bg-red-900/30 text-red-800 dark:text-red-200 font-bold"
          >
             <div className="flex items-center gap-2">
                <Octagon size={20} /> Strictly Contraindicated Drugs (Always Unsafe)
             </div>
             {showContraindicated ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
          </button>

          {showContraindicated && (
             <div className="p-4 grid gap-3 md:grid-cols-2 animate-fade-in">
                {ALWAYS_CONTRAINDICATED.map((drug, i) => (
                   <div key={i} className="bg-white dark:bg-deep-card p-3 rounded-xl border border-red-100 dark:border-red-900/30">
                      <p className="font-bold text-red-700 dark:text-red-400">{drug.name}</p>
                      <p className="text-xs text-gray-600 dark:text-gray-300 mt-1">{drug.reason}</p>
                   </div>
                ))}
             </div>
          )}
       </div>

      {/* Guide Section */}
      <div className="space-y-4">
        <div className="flex items-center justify-between mb-2 px-2">
          <h3 className="text-xl font-bold text-gray-800 dark:text-white">
             {trimesterTitle} Medicines Guide
          </h3>
          <span className="text-xs font-medium text-gray-500 bg-gray-100 dark:bg-indigo-900/50 px-3 py-1 rounded-full">
            {isPostpartum ? 'Safe for Baby' : `Week ${currentWeek}`}
          </span>
        </div>

        {guideData?.map((category, idx) => (
          <div key={idx} className="bg-white dark:bg-deep-card rounded-2xl shadow-sm border border-gray-100 dark:border-indigo-800 overflow-hidden">
            <button 
              onClick={() => toggleCategory(idx)}
              className="w-full flex items-center justify-between p-5 text-left hover:bg-gray-50 dark:hover:bg-white/5 transition-colors"
            >
              <h4 className="font-bold text-lg text-gray-800 dark:text-white flex items-center gap-2">
                {category.category}
              </h4>
              {expandedCategory === idx ? <ChevronUp size={20} className="text-gray-400" /> : <ChevronDown size={20} className="text-gray-400" />}
            </button>

            {expandedCategory === idx && (
              <div className="p-5 pt-0 border-t border-gray-100 dark:border-indigo-800/50 animate-fade-in">
                <div className="mt-4 grid gap-4 md:grid-cols-2">
                  {/* Safe Column */}
                  <div className="bg-green-50 dark:bg-green-900/10 p-4 rounded-xl border border-green-100 dark:border-green-900/30">
                     <h5 className="flex items-center gap-2 font-bold text-green-700 dark:text-green-400 mb-2 text-sm uppercase tracking-wide">
                        <ShieldCheck size={16} /> Safe
                     </h5>
                     <ul className="space-y-1">
                        {category.safe.map((m, i) => (
                           <li key={i} className="text-sm text-gray-700 dark:text-gray-300">• {m}</li>
                        ))}
                     </ul>
                  </div>

                  {/* Avoid Column */}
                  <div className="bg-red-50 dark:bg-red-900/10 p-4 rounded-xl border border-red-100 dark:border-red-900/30">
                     <h5 className="flex items-center gap-2 font-bold text-red-700 dark:text-red-400 mb-2 text-sm uppercase tracking-wide">
                        <XCircle size={16} /> Avoid
                     </h5>
                     <ul className="space-y-1">
                        {category.avoid.map((m, i) => (
                           <li key={i} className="text-sm text-gray-700 dark:text-gray-300">• {m}</li>
                        ))}
                     </ul>
                  </div>
                </div>

                {/* Caution */}
                {category.caution.length > 0 && (
                  <div className="mt-4 bg-yellow-50 dark:bg-yellow-900/10 p-4 rounded-xl border border-yellow-100 dark:border-yellow-900/30">
                     <h5 className="flex items-center gap-2 font-bold text-yellow-700 dark:text-yellow-400 mb-2 text-sm uppercase tracking-wide">
                        <AlertTriangle size={16} /> Use with Caution
                     </h5>
                     <p className="text-sm text-gray-700 dark:text-gray-300">
                        {category.caution.join(', ')}
                     </p>
                  </div>
                )}

                {/* Note */}
                {category.note && (
                   <div className="mt-4 text-sm italic text-gray-500 dark:text-gray-400 border-l-4 border-bloom-DEFAULT pl-3">
                      Note: {category.note}
                   </div>
                )}
              </div>
            )}
          </div>
        ))}

        <div className="p-4 bg-blue-50 dark:bg-blue-900/20 rounded-xl text-sm text-blue-800 dark:text-blue-200 border border-blue-100 dark:border-blue-900/30 flex items-start gap-3">
             <Info className="shrink-0 mt-0.5" size={18} />
             <p>This list assumes a low-risk {isPostpartum ? 'recovery' : 'pregnancy'}. If you have underlying conditions (Diabetes, Hypertension, etc.), always consult your doctor before taking "Safe" medications.</p>
        </div>
      </div>
    </div>
  );
};

